'use client';
import { useEffect, useState, useCallback, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { getOrganizationsForUser } from '@/lib/organization';
import { getUserRole, updateUserRole, UserRole, ROLE_LABELS, ROLE_COLORS } from '@/lib/roles';
import { getOrgMembersWithEmails } from '@/lib/actions/adminActions';
import {
  Users, ShieldCheck, UserPlus, Mail, Loader, CheckCircle,
  MoreVertical, Trash2, Edit2, Send, Building2, AlertCircle, RefreshCw, LayoutGrid, List,
  FileText, Upload, Plus, Download, X, Files
} from 'lucide-react';
import { useViewMode } from '@/components/ui/ViewModeProvider';

interface Template {
  id: string;
  name: string;
  type: 'pdf' | 'docx' | 'xlsx';
  storage_path: string;
}

interface OrgMember {
  user_id: string;
  role: UserRole;
  email?: string;
  created_at: string;
}

export default function AdminPage() {
  const { viewMode, setViewMode } = useViewMode();
  const router = useRouter();
  const [orgId, setOrgId] = useState<string | null>(null);
  const [orgName, setOrgName] = useState('');
  const [members, setMembers] = useState<OrgMember[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);

  // Einladung
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<UserRole>('employee');
  const [inviting, setInviting] = useState(false);
  const [inviteSuccess, setInviteSuccess] = useState('');
  const [inviteError, setInviteError] = useState('');

  // Tab-Management
  const [activeTab, setActiveTab] = useState<'users' | 'templates'>('users');

  // Vorlagen
  const [templates, setTemplates] = useState<Template[]>([]);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState('');

  // Rollenänderung
  const [updatingRole, setUpdatingRole] = useState<string | null>(null);

  useEffect(() => {
    const supabase = createClient();
    supabase.auth.getUser().then(async ({ data }) => {
      if (!data.user) { router.push('/auth/login'); return; }
      setCurrentUserId(data.user.id);

      const orgs = await getOrganizationsForUser(data.user.id);
      if (orgs.length === 0) return;
      const org = orgs[0] as { id: string; name: string };

      // Nur Admins dürfen auf diese Seite
      const role = await getUserRole(data.user.id, org.id).catch(() => null);
      if (role !== 'admin') { router.push('/dashboard'); return; }

      setOrgId(org.id);
      setOrgName(org.name);
    });
  }, [router]);

  const loadMembers = useCallback(async () => {
    if (!orgId) return;
    setLoading(true);
    try {
      // Nutzt die neue Server Action statt clientseitige Admin-Calls (behebt 403)
      const data = await getOrgMembersWithEmails(orgId);
      setMembers(data as OrgMember[]);
    } catch (err) {
      console.error('Fehler beim Laden der Mitglieder:', err);
    } finally {
      setLoading(false);
    }
  }, [orgId]);

  const loadTemplates = useCallback(async () => {
    if (!orgId) return;
    try {
      const supabase = createClient();
      const { data } = await supabase
        .from('document_templates')
        .select('*')
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      setTemplates((data as Template[]) || []);
    } catch { /* ignorieren */ }
  }, [orgId]);

  useEffect(() => { 
    if (orgId) {
      loadMembers();
      loadTemplates();
    }
  }, [orgId, loadMembers, loadTemplates]);

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!orgId || !inviteEmail) return;
    setInviting(true);
    setInviteError('');
    setInviteSuccess('');

    try {
      const supabase = createClient();
      // Einladung via Supabase auth (benötigt ggf. ebenfalls Admin-API, hier Client-Fallback)
      const { error } = await supabase.auth.admin.inviteUserByEmail(inviteEmail, {
        data: { organization_id: orgId, role: inviteRole },
        redirectTo: `${window.location.origin}/auth/accept-invite?org=${orgId}&role=${inviteRole}`,
      });

      if (error) throw error;
      setInviteSuccess(`Einladung an ${inviteEmail} gesendet!`);
      setInviteEmail('');
      loadMembers(); // Liste aktualisieren
    } catch (err) {
      setInviteError(`Supabase Admin-Rechte erforderlich. Einladungs-URL: ${window.location.origin}/invite?org=${orgId}&role=${inviteRole}`);
    } finally {
      setInviting(false);
    }
  };

  const handleRoleChange = async (memberId: string, newRole: UserRole) => {
    if (!orgId) return;
    setUpdatingRole(memberId);
    try {
      await updateUserRole(memberId, orgId, newRole);
      setMembers(prev => prev.map(m => m.user_id === memberId ? { ...m, role: newRole } : m));
    } finally {
      setUpdatingRole(null);
    }
  };

  const handleRemoveMember = async (memberId: string) => {
    if (!orgId || !confirm('Benutzer wirklich entfernen?')) return;
    const supabase = createClient();
    await supabase
      .from('user_roles')
      .delete()
      .eq('user_id', memberId)
      .eq('organization_id', orgId);
    setMembers(prev => prev.filter(m => m.user_id !== memberId));
  };

  const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !orgId) return;

    const ext = file.name.split('.').pop()?.toLowerCase();
    if (!['pdf', 'docx', 'xlsx'].includes(ext || '')) {
      setUploadError('Nur PDF, DOCX und XLSX werden unterstützt');
      return;
    }

    setUploading(true);
    setUploadError('');
    try {
      const supabase = createClient();
      const path = `${orgId}/${Date.now()}_${file.name}`;

      const { error: storageError } = await supabase.storage
        .from('templates')
        .upload(path, file);
      if (storageError) throw storageError;

      const { data, error: dbError } = await supabase
        .from('document_templates')
        .insert([{
          name: file.name.replace(`.${ext}`, ''),
          type: ext as any,
          storage_path: path,
          organization_id: orgId
        }])
        .select()
        .single();
      if (dbError) throw dbError;

      setTemplates(prev => [data as Template, ...prev]);
    } catch (err) {
      setUploadError((err as Error).message);
    } finally {
      setUploading(false);
    }
  };

  const handleRemoveTemplate = async (template: Template) => {
    if (!confirm(`Vorlage "${template.name}" wirklich löschen?`)) return;
    const supabase = createClient();
    await supabase.storage.from('templates').remove([template.storage_path]);
    await supabase.from('document_templates').delete().eq('id', template.id);
    setTemplates(prev => prev.filter(t => t.id !== template.id));
  };

  const stats = useMemo(() => ({
    total: members.length,
    admins: members.filter(m => m.role === 'admin').length,
    approvers: members.filter(m => m.role === 'approver').length,
    employees: members.filter(m => m.role === 'employee').length,
    templates: templates.length,
  }), [members, templates]);

  return (
    <div className="p-6 md:p-8 w-full animate-fade-in pb-20">
      {/* Header */}
      <div className="flex items-start justify-between mb-6 flex-wrap gap-4">
        <div>
          <h1 className="text-2xl font-black tracking-tight flex items-center gap-2" style={{ color: 'var(--text-base)' }}>
            <ShieldCheck size={22} style={{ color: 'var(--primary)' }} />
            Administration
          </h1>
          <p className="text-sm mt-1 flex items-center gap-1.5" style={{ color: 'var(--text-muted)' }}>
            <Building2 size={12} /> {orgName}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <div className="flex items-center bg-[var(--bg-elevated)] p-1 rounded-xl border" style={{ borderColor: 'var(--border)' }}>
            <button
              onClick={() => setViewMode('list')}
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
              title="Listenansicht"
            >
              <List size={14} />
            </button>
            <button
              onClick={() => setViewMode('grid')}
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
              title="Rasteransicht"
            >
              <LayoutGrid size={14} />
            </button>
          </div>
          <button onClick={loadMembers} className="btn-secondary shrink-0">
            <RefreshCw size={13} /> Aktualisieren
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
        {[
          { label: 'Mitglieder gesamt', value: stats.total, color: 'var(--primary)', bg: 'var(--primary-light)' },
          { label: 'Administratoren', value: stats.admins, color: 'var(--danger)', bg: 'var(--danger-light)' },
          { label: 'Genehmiger', value: stats.approvers, color: 'var(--warning)', bg: 'var(--warning-light)' },
          { label: 'Mitarbeiter', value: stats.employees, color: 'var(--success)', bg: 'var(--success-light)' },
        ].map(s => (
          <div key={s.label} className="kpi-card">
            <div className="p-2 rounded-xl inline-flex mb-2" style={{ background: s.bg }}>
              <Users size={16} style={{ color: s.color }} />
            </div>
            <p className="text-2xl font-black" style={{ color: 'var(--text-base)' }}>{s.value}</p>
            <p className="text-xs" style={{ color: 'var(--text-muted)' }}>{s.label}</p>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 mb-6 p-1 bg-[var(--bg-elevated)] rounded-xl border w-fit" style={{ borderColor: 'var(--border)' }}>
        <button
          onClick={() => setActiveTab('users')}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all ${
            activeTab === 'users' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'
          }`}
        >
          <Users size={14} /> Benutzer
        </button>
        <button
          onClick={() => setActiveTab('templates')}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all ${
            activeTab === 'templates' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'
          }`}
        >
          <Files size={14} /> Vorlagen
        </button>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Haupt-Inhalt */}
        <div className="lg:col-span-2">
          {activeTab === 'users' ? (
            <div className="card overflow-hidden">
              <div className="p-5 border-b flex items-center justify-between" style={{ borderColor: 'var(--border)' }}>
                <h2 className="text-sm font-bold" style={{ color: 'var(--text-base)' }}>
                  Benutzerverwaltung
                </h2>
                <span className="badge badge-primary">{stats.total} Mitglieder</span>
              </div>

              {loading ? (
                <div className="p-6 space-y-3">
                  {[1,2,3].map(i => <div key={i} className="skeleton h-14 rounded-xl" />)}
                </div>
              ) : members.length === 0 ? (
                <div className="text-center py-12">
                  <Users size={32} className="mx-auto mb-3 opacity-20" />
                  <p className="text-sm" style={{ color: 'var(--text-muted)' }}>Noch keine Mitglieder</p>
                </div>
              ) : viewMode === 'list' ? (
                <div className="overflow-x-auto">
                  <table className="data-table">
                    <thead>
                      <tr>
                        <th>Benutzer</th>
                        <th>Rolle</th>
                        <th>Seit</th>
                        <th>Aktionen</th>
                      </tr>
                    </thead>
                    <tbody>
                      {members.map(m => (
                        <tr key={m.user_id}>
                          <td>
                            <div className="flex items-center gap-2.5">
                              <div className="w-8 h-8 rounded-full bg-gradient-to-br from-[var(--primary)] to-[#8b5cf6] flex items-center justify-center text-white font-bold text-xs shrink-0">
                                {(m.email || m.user_id || '?').charAt(0).toUpperCase()}
                              </div>
                              <div>
                                <p className="text-sm font-medium truncate max-w-[150px]" style={{ color: 'var(--text-base)' }}>
                                  {m.email || m.user_id.slice(0, 8) + '...'}
                                </p>
                                {m.user_id === currentUserId && (
                                  <span className="text-[9px] font-bold" style={{ color: 'var(--primary)' }}>Du</span>
                                )}
                              </div>
                            </div>
                          </td>
                          <td>
                            <div className="relative">
                              <select
                                value={m.role}
                                onChange={e => handleRoleChange(m.user_id, e.target.value as UserRole)}
                                disabled={updatingRole === m.user_id || m.user_id === currentUserId}
                                className="text-xs rounded-lg px-2 py-1.5 pr-6 border appearance-none cursor-pointer disabled:opacity-50"
                                style={{
                                  background: 'var(--bg-elevated)',
                                  borderColor: 'var(--border)',
                                  color: 'var(--text-base)',
                                }}
                              >
                                <option value="admin">Administrator</option>
                                <option value="approver">Genehmiger</option>
                                <option value="employee">Mitarbeiter</option>
                              </select>
                              {updatingRole === m.user_id && (
                                <Loader size={10} className="absolute right-2 top-1/2 -translate-y-1/2 animate-spin" style={{ color: 'var(--primary)' }} />
                              )}
                            </div>
                          </td>
                          <td>
                            <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                              {new Date(m.created_at).toLocaleDateString('de-DE')}
                            </span>
                          </td>
                          <td>
                            {m.user_id !== currentUserId && (
                              <button
                                onClick={() => handleRemoveMember(m.user_id)}
                                className="btn-ghost p-1.5 text-[var(--text-muted)] hover:text-[var(--danger)]"
                                title="Entfernen"
                              >
                                <Trash2 size={13} />
                              </button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-5">
                   {members.map(m => (
                     <div key={m.user_id} className="border p-4 rounded-xl flex flex-col gap-3 relative transition-all hover:shadow-md" style={{ borderColor: 'var(--border)', background: 'var(--bg-surface)' }}>
                       <div className="flex justify-between items-start">
                         <div className="flex items-center gap-2.5">
                            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-[var(--primary)] to-[#8b5cf6] flex items-center justify-center text-white font-bold text-sm shrink-0">
                               {(m.email || m.user_id || '?').charAt(0).toUpperCase()}
                            </div>
                            <div>
                               <p className="text-sm font-medium truncate max-w-[150px]" style={{ color: 'var(--text-base)' }}>
                                 {m.email || m.user_id.slice(0, 8) + '...'}
                               </p>
                               {m.user_id === currentUserId && (
                                 <span className="text-[10px] font-bold" style={{ color: 'var(--primary)' }}>Du</span>
                               )}
                            </div>
                         </div>
                         {m.user_id !== currentUserId && (
                            <button
                              onClick={() => handleRemoveMember(m.user_id)}
                              className="btn-ghost p-1.5 text-[var(--text-muted)] hover:text-[var(--danger)]"
                              title="Entfernen"
                            >
                              <Trash2 size={13} />
                            </button>
                          )}
                       </div>
                       <div className="flex justify-between items-center mt-2 pt-3 border-t" style={{ borderColor: 'var(--border)' }}>
                         <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                            Seit {new Date(m.created_at).toLocaleDateString('de-DE')}
                         </span>
                         <div className="relative">
                            <select
                              value={m.role}
                              onChange={e => handleRoleChange(m.user_id, e.target.value as UserRole)}
                              disabled={updatingRole === m.user_id || m.user_id === currentUserId}
                              className="text-xs font-semibold rounded-lg px-2 py-1.5 pr-6 border appearance-none cursor-pointer disabled:opacity-50"
                              style={{
                                background: 'var(--bg-elevated)',
                                borderColor: 'var(--border)',
                                color: 'var(--text-base)',
                              }}
                            >
                              <option value="admin">Administrator</option>
                              <option value="approver">Genehmiger</option>
                              <option value="employee">Mitarbeiter</option>
                            </select>
                            {updatingRole === m.user_id && (
                              <Loader size={10} className="absolute right-2 top-1/2 -translate-y-1/2 animate-spin" style={{ color: 'var(--primary)' }} />
                            )}
                         </div>
                       </div>
                     </div>
                   ))}
                </div>
              )}
            </div>
          ) : (
            <div className="card p-5">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h2 className="text-sm font-bold" style={{ color: 'var(--text-base)' }}>
                    Dokument-Vorlagen
                  </h2>
                  <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
                    PDF, Word oder Excel Anträge verwalten
                  </p>
                </div>
                <div className="relative">
                  <input
                    type="file"
                    id="template-upload"
                    className="hidden"
                    onChange={handleTemplateUpload}
                    accept=".pdf,.docx,.xlsx"
                  />
                  <label
                    htmlFor="template-upload"
                    className="btn-primary cursor-pointer"
                  >
                    {uploading ? <RefreshCw size={13} className="animate-spin" /> : <Upload size={13} />}
                    Hochladen
                  </label>
                </div>
              </div>

              {uploadError && <div className="p-3 bg-[var(--danger-light)] text-[var(--danger)] text-xs rounded-xl mb-4">{uploadError}</div>}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {templates.map(t => (
                  <div key={t.id} className="p-3 rounded-xl border flex items-center justify-between group transition-all hover:border-[var(--primary)]" style={{ borderColor: 'var(--border)', background: 'var(--bg-elevated)' }}>
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-lg ${
                        t.type === 'pdf' ? 'bg-red-500/10 text-red-500' :
                        t.type === 'xlsx' ? 'bg-green-500/10 text-green-500' :
                        'bg-blue-500/10 text-blue-500'
                      }`}>
                        <FileText size={16} />
                      </div>
                      <div className="min-w-0">
                        <p className="text-xs font-bold truncate" style={{ color: 'var(--text-base)' }}>{t.name}</p>
                        <p className="text-[10px] uppercase font-bold tracking-widest" style={{ color: 'var(--text-subtle)' }}>{t.type}</p>
                      </div>
                    </div>
                    <button
                      onClick={() => handleRemoveTemplate(t)}
                      className="p-1.5 text-[var(--text-muted)] hover:text-[var(--danger)] transition-colors"
                    >
                      <Trash2 size={13} />
                    </button>
                  </div>
                ))}
                {templates.length === 0 && (
                  <div className="col-span-2 text-center py-10 opacity-30">
                    <Files size={32} className="mx-auto mb-2" />
                    <p className="text-sm font-medium">Noch keine Vorlagen</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Einladungs-Panel */}
        <div className="flex flex-col gap-4">
          <div className="card p-5">
            <h2 className="text-sm font-bold mb-4 flex items-center gap-2" style={{ color: 'var(--text-base)' }}>
              <UserPlus size={15} style={{ color: 'var(--primary)' }} />
              Benutzer einladen
            </h2>
            <form onSubmit={handleInvite} className="space-y-3">
              <div>
                <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>E-Mail-Adresse</label>
                <input
                  type="email"
                  value={inviteEmail}
                  onChange={e => setInviteEmail(e.target.value)}
                  placeholder="kollege@firma.de"
                  className="w-full px-3 py-2.5 rounded-lg border text-sm"
                  required
                />
              </div>
              <div>
                <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>Rolle zuweisen</label>
                <select
                  value={inviteRole}
                  onChange={e => setInviteRole(e.target.value as UserRole)}
                  className="w-full px-3 py-2.5 rounded-lg border text-sm"
                >
                  <option value="employee">Mitarbeiter</option>
                  <option value="approver">Genehmiger</option>
                  <option value="admin">Administrator</option>
                </select>
              </div>

              {inviteSuccess && (
                <div className="flex items-start gap-2 p-2.5 rounded-lg text-xs" style={{ background: 'var(--success-light)', color: 'var(--success)' }}>
                  <CheckCircle size={13} className="shrink-0 mt-0.5" />
                  {inviteSuccess}
                </div>
              )}
              {inviteError && (
                <div className="flex items-start gap-2 p-2.5 rounded-lg text-xs" style={{ background: 'var(--warning-light)', color: 'var(--warning)' }}>
                  <AlertCircle size={13} className="shrink-0 mt-0.5" />
                  <span className="break-all">{inviteError}</span>
                </div>
              )}

              <button type="submit" disabled={inviting} className="btn-primary w-full justify-center">
                {inviting ? <Loader size={13} className="animate-spin" /> : <Send size={13} />}
                {inviting ? 'Sende Einladung...' : 'Einladung senden'}
              </button>
            </form>
          </div>

          {/* Rollen-Legende */}
          <div className="card p-5">
            <h2 className="text-sm font-bold mb-3" style={{ color: 'var(--text-base)' }}>Rollen-Übersicht</h2>
            <div className="space-y-2.5">
              {([
                { role: 'admin', desc: 'Vollzugriff, Benutzerverwaltung, alle Anträge genehmigen' },
                { role: 'approver', desc: 'Anträge genehmigen und ablehnen' },
                { role: 'employee', desc: 'Anträge einreichen und eigene anzeigen' },
              ] as { role: UserRole; desc: string }[]).map(({ role: r, desc }) => (
                <div key={r} className="flex items-start gap-2">
                  <span className={`badge badge shrink-0 mt-0.5 ${ROLE_COLORS[r]}`}>
                    {ROLE_LABELS[r]}
                  </span>
                  <p className="text-xs flex-1" style={{ color: 'var(--text-muted)' }}>{desc}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState, useCallback, useRef } from 'react';
import { createClient } from '@/lib/supabase/client';
import { getOrganizationsForUser } from '@/lib/organization';
import { getVacationRequestsForOrg, VacationRequest } from '@/lib/vacation';
import {
  format, parseISO, startOfMonth, endOfMonth, eachDayOfInterval,
  getDay, addMonths, subMonths, isSameDay, isWeekend, isSameMonth,
  startOfWeek, endOfWeek, addDays, differenceInCalendarDays,
} from 'date-fns';
import { de } from 'date-fns/locale';
import {
  ChevronLeft, ChevronRight, CalendarDays, RefreshCw, Calendar,
  Clock, CheckCircle, XCircle, Info, Download, Plus,
} from 'lucide-react';
import Link from 'next/link';
import CalendarSync from '@/components/CalendarSync';
import { getUserRole, UserRole, canApprove } from '@/lib/roles';

type ViewMode = 'month' | 'week';

interface CalendarEvent {
  id: string;
  title: string;
  from: string;
  to: string;
  type: 'approved' | 'pending' | 'rejected' | 'sync';
  reason?: string;
  userId?: string;
}

export default function CalendarPage() {
  const [orgId, setOrgId] = useState<string | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [userId, setUserId] = useState<string | null>(null);
  const [requests, setRequests] = useState<VacationRequest[]>([]);
  const [syncEvents, setSyncEvents] = useState<CalendarEvent[]>([]);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<ViewMode>('month');
  const [loading, setLoading] = useState(true);
  const [showSync, setShowSync] = useState(false);
  const [hoveredEvent, setHoveredEvent] = useState<CalendarEvent | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const supabase = createClient();
    supabase.auth.getUser().then(async ({ data }) => {
      const uid = data.user?.id;
      if (!uid) return;
      setUserId(uid);
      const orgs = await getOrganizationsForUser(uid);
      const firstOrg = orgs.find(o => o !== null) as { id: string; name: string } | undefined;
      if (firstOrg) {
        setOrgId(firstOrg.id);
        const r = await getUserRole(uid, firstOrg.id).catch(() => 'employee' as UserRole);
        setRole(r);
      }
    });
  }, []);

  const loadData = useCallback(async () => {
    if (!orgId) return;
    setLoading(true);
    try {
      const data = await getVacationRequestsForOrg(orgId);
      setRequests(data);

      // Load synced calendar events
      const supabase = createClient();
      const { data: evData } = await supabase
        .from('calendar_events')
        .select('*')
        .eq('organization_id', orgId);
      if (evData) {
        setSyncEvents(evData.map((e: {id: string; title: string; start_date: string; end_date: string; description?: string; user_id?: string}) => ({
          id: e.id, title: e.title, from: e.start_date, to: e.end_date,
          type: 'sync' as const, reason: e.description, userId: e.user_id,
        })));
      }
    } finally {
      setLoading(false);
    }
  }, [orgId]);

  useEffect(() => { loadData(); }, [loadData]);

  // Combine all events
  const allEvents: CalendarEvent[] = [
    ...requests.map(r => ({
      id: r.id,
      title: r.reason || 'Urlaub',
      from: r.from,
      to: r.to,
      type: r.status as 'approved' | 'pending' | 'rejected',
      reason: r.reason,
      userId: r.user_id,
    })),
    ...syncEvents,
  ];

  const getDayEvents = (date: Date): CalendarEvent[] =>
    allEvents.filter(e => {
      const from = parseISO(e.from);
      const to   = parseISO(e.to);
      return date >= from && date <= to;
    });

  const today = new Date();
  const weekdays = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So'];

  const eventTypeConfig = {
    approved: { label: 'Genehmigt',   cls: 'cal-event-approved', Icon: CheckCircle },
    pending:  { label: 'Ausstehend',  cls: 'cal-event-pending',  Icon: Clock },
    rejected: { label: 'Abgelehnt',   cls: 'cal-event-rejected', Icon: XCircle },
    sync:     { label: 'Synchronisiert', cls: 'cal-event-sync',  Icon: RefreshCw },
  };

  // Month grid
  const monthDays = eachDayOfInterval({ start: startOfMonth(currentDate), end: endOfMonth(currentDate) });
  const firstDayOffset = (getDay(monthDays[0]) + 6) % 7;

  // Week grid
  const weekStart = startOfWeek(currentDate, { weekStartsOn: 1 });
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));

  const navigate = (dir: 1 | -1) => {
    setCurrentDate(d =>
      viewMode === 'month'
        ? dir === 1 ? addMonths(d, 1) : subMonths(d, 1)
        : addDays(d, dir * 7)
    );
  };

  const monthLabel = format(currentDate, 'MMMM yyyy', { locale: de });
  const weekLabel = `${format(weekStart, 'dd.MM.')} – ${format(addDays(weekStart, 6), 'dd.MM.yyyy')}`;

  return (
    <div className="p-6 md:p-8 w-full animate-fade-in">
      {/* ─── Header ─────────────────────────────────────── */}
      <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-black tracking-tight flex items-center gap-2" style={{ color: 'var(--text-base)' }}>
            <CalendarDays size={22} style={{ color: 'var(--primary)' }} />
            Kalender
          </h1>
          <p className="text-sm mt-1" style={{ color: 'var(--text-muted)' }}>
            Urlaubsübersicht und Termine
          </p>
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          {/* View Toggle */}
          <div className="flex rounded-xl overflow-hidden border" style={{ borderColor: 'var(--border)' }}>
            {(['month', 'week'] as ViewMode[]).map(v => (
              <button
                key={v}
                onClick={() => setViewMode(v)}
                className={`px-3 py-1.5 text-xs font-semibold transition-all ${
                  viewMode === v
                    ? 'bg-[var(--primary)] text-white'
                    : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'
                }`}
                style={{ background: viewMode === v ? 'var(--primary)' : 'var(--bg-surface)' }}
              >
                {v === 'month' ? 'Monat' : 'Woche'}
              </button>
            ))}
          </div>

          <button
            onClick={() => setShowSync(true)}
            className="btn-secondary"
          >
            <RefreshCw size={13} />
            Sync
          </button>

          <Link href="/dashboard/requests" className="btn-primary">
            <Plus size={13} />
            Neuer Antrag
          </Link>
        </div>
      </div>

      {/* ─── Navigation ─────────────────────────────────── */}
      <div className="flex items-center gap-3 mb-4">
        <button onClick={() => navigate(-1)} className="btn-ghost p-2">
          <ChevronLeft size={16} />
        </button>
        <button onClick={() => setCurrentDate(new Date())} className="btn-ghost text-xs px-3">
          Heute
        </button>
        <button onClick={() => navigate(1)} className="btn-ghost p-2">
          <ChevronRight size={16} />
        </button>
        <span className="text-base font-bold capitalize" style={{ color: 'var(--text-base)' }}>
          {viewMode === 'month' ? monthLabel : weekLabel}
        </span>
        {loading && <RefreshCw size={14} className="animate-spin ml-2" style={{ color: 'var(--text-muted)' }} />}
      </div>

      {/* ─── Legend ─────────────────────────────────────── */}
      <div className="flex items-center gap-4 mb-4 flex-wrap">
        {Object.entries(eventTypeConfig).map(([key, cfg]) => (
          <div key={key} className="flex items-center gap-1.5">
            <div className={`h-2.5 w-4 rounded-sm cal-event-${key}`}
              style={{ background: key === 'approved' ? 'rgba(16,185,129,0.2)' : key === 'pending' ? 'rgba(245,158,11,0.2)' : key === 'rejected' ? 'rgba(239,68,68,0.2)' : 'rgba(139,92,246,0.2)' }}
            />
            <span className="text-[11px] font-medium" style={{ color: 'var(--text-muted)' }}>{cfg.label}</span>
          </div>
        ))}
      </div>

      {/* ─── Calendar Grid ──────────────────────────────── */}
      <div className="card overflow-hidden">
        {/* Weekday Headers */}
        <div className="grid grid-cols-7 border-b" style={{ borderColor: 'var(--border)', background: 'var(--bg-elevated)' }}>
          {weekdays.map(d => (
            <div key={d} className="text-center py-3 text-[11px] font-bold uppercase tracking-widest" style={{ color: 'var(--text-subtle)' }}>
              {d}
            </div>
          ))}
        </div>

        {/* Month View */}
        {viewMode === 'month' && (
          <div className="grid grid-cols-7">
            {/* Empty offset cells */}
            {Array.from({ length: firstDayOffset }).map((_, i) => (
              <div
                key={`empty-${i}`}
                className="cal-day"
                style={{ background: 'var(--bg-elevated)', opacity: 0.4 }}
              />
            ))}

            {monthDays.map((day, idx) => {
              const isToday_ = isSameDay(day, today);
              const isWknd = isWeekend(day);
              const dayEvents = getDayEvents(day);
              const totalCells = firstDayOffset + monthDays.length;
              const isLastRow = idx >= totalCells - (totalCells % 7 || 7);
              const maxVisible = 3;

              return (
                <div
                  key={day.toISOString()}
                  className={`cal-day ${isToday_ ? 'today' : ''} ${isWknd ? 'weekend' : ''}`}
                  style={{
                    borderBottom: isLastRow ? 'none' : `1px solid var(--border)`,
                    borderRight: `1px solid var(--border)`,
                  }}
                >
                  <div className="flex items-start justify-between mb-1">
                    <span className={`text-[11px] font-bold leading-none flex items-center justify-center ${
                      isToday_
                        ? 'w-6 h-6 rounded-full bg-[var(--primary)] text-white'
                        : isWknd ? 'text-[var(--text-subtle)]' : 'text-[var(--text-muted)]'
                    }`}>
                      {format(day, 'd')}
                    </span>
                  </div>

                  {/* Events */}
                  <div className="space-y-0.5">
                    {dayEvents.slice(0, maxVisible).map(ev => (
                      <Link
                        key={ev.id}
                        href={`/dashboard/requests/${ev.id}`}
                        className={`cal-event ${eventTypeConfig[ev.type].cls} no-underline`}
                        title={ev.title}
                      >
                        {ev.title}
                      </Link>
                    ))}
                    {dayEvents.length > maxVisible && (
                      <div className="text-[9px] font-semibold" style={{ color: 'var(--text-muted)' }}>
                        +{dayEvents.length - maxVisible} mehr
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* Week View */}
        {viewMode === 'week' && (
          <div className="grid grid-cols-7" style={{ minHeight: '500px' }}>
            {weekDays.map(day => {
              const isToday_ = isSameDay(day, today);
              const isWknd = isWeekend(day);
              const dayEvents = getDayEvents(day);

              return (
                <div
                  key={day.toISOString()}
                  className={`cal-day flex flex-col ${isToday_ ? 'today' : ''} ${isWknd ? 'weekend' : ''}`}
                  style={{
                    minHeight: '400px',
                    borderRight: `1px solid var(--border)`,
                  }}
                >
                  <div className="flex items-center gap-1 mb-2">
                    <span className={`text-xs font-bold flex items-center justify-center ${
                      isToday_
                        ? 'w-6 h-6 rounded-full bg-[var(--primary)] text-white'
                        : 'text-[var(--text-muted)]'
                    }`}>
                      {format(day, 'd')}
                    </span>
                  </div>

                  <div className="flex flex-col gap-1 flex-1">
                    {dayEvents.map(ev => (
                      <Link
                        key={ev.id}
                        href={`/dashboard/requests/${ev.id}`}
                        className={`cal-event ${eventTypeConfig[ev.type].cls} no-underline py-1.5 px-2 rounded-lg text-[11px] flex items-center gap-1`}
                      >
                        {ev.title}
                      </Link>
                    ))}
                    {dayEvents.length === 0 && isToday_ && (
                      <Link href="/dashboard/requests" className="text-[10px] text-[var(--primary)] border border-dashed border-[var(--primary-light)] rounded-lg p-1.5 text-center no-underline hover:bg-[var(--primary-light)] transition-colors">
                        + Antrag
                      </Link>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ─── Upcoming Requests ──────────────────────────── */}
      {requests.length > 0 && (
        <div className="mt-6 card p-5 animate-fade-in-d2">
          <h2 className="text-sm font-bold mb-4" style={{ color: 'var(--text-base)' }}>
            Aktuelle Anträge
          </h2>
          <div className="space-y-2">
            {requests.slice(0, 8).map(r => {
              const cfg = eventTypeConfig[r.status as keyof typeof eventTypeConfig];
              return (
                <Link
                  key={r.id}
                  href={`/dashboard/requests/${r.id}`}
                  className="flex items-center gap-3 p-3 rounded-xl border no-underline group hover:border-[rgba(99,102,241,0.2)] transition-all"
                  style={{ borderColor: 'var(--border)', background: 'var(--bg-elevated)' }}
                >
                  <div className={`w-2 h-2 rounded-full shrink-0 ${
                    r.status === 'approved' ? 'bg-[var(--success)]' :
                    r.status === 'rejected' ? 'bg-[var(--danger)]' : 'bg-[var(--warning)]'
                  }`} />
                  <div className="text-sm" style={{ color: 'var(--text-base)' }}>
                    <span className="font-semibold">{format(parseISO(r.from), 'dd.MM.yyyy')}</span>
                    {' – '}
                    <span className="font-semibold">{format(parseISO(r.to), 'dd.MM.yyyy')}</span>
                    <span className="text-xs ml-2" style={{ color: 'var(--text-muted)' }}>
                      ({differenceInCalendarDays(parseISO(r.to), parseISO(r.from)) + 1} Tage)
                    </span>
                  </div>
                  {r.reason && <div className="text-xs truncate flex-1" style={{ color: 'var(--text-muted)' }}>{r.reason}</div>}
                  <span className={`badge ${cfg?.label === 'Genehmigt' ? 'badge-approved' : cfg?.label === 'Ausstehend' ? 'badge-pending' : 'badge-rejected'} shrink-0 ml-auto`}>
                    {cfg?.label}
                  </span>
                </Link>
              );
            })}
          </div>
        </div>
      )}

      {/* ─── Sync Modal ─────────────────────────────────── */}
      {showSync && (
        <CalendarSync
          orgId={orgId || ''}
          userId={userId || ''}
          onClose={() => setShowSync(false)}
          onSynced={loadData}
        />
      )}
    </div>
  );
}

'use client';
import { useEffect, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { createClient } from '@/lib/supabase/client';
import { getOrganizationsForUser } from '@/lib/organization';
import { getVacationRequestsForOrg, VacationRequest } from '@/lib/vacation';
import { getUserRole, UserRole, canApprove, ROLE_LABELS } from '@/lib/roles';
import { format, parseISO, differenceInCalendarDays, isToday, isFuture } from 'date-fns';
import { de } from 'date-fns/locale';
import {
  ClipboardList, CheckCircle, Clock, XCircle, CalendarDays,
  Plus, ArrowRight, RefreshCw, Users, TrendingUp, Mail,
  Building2, ShieldCheck, LayoutGrid, List
} from 'lucide-react';
import { useViewMode } from '@/components/ui/ViewModeProvider';

export default function Dashboard() {
  const { viewMode, setViewMode } = useViewMode();
  const [user, setUser] = useState<{ id: string; email: string } | null>(null);
  const [org, setOrg] = useState<{ id: string; name: string } | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [requests, setRequests] = useState<VacationRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    const supabase = createClient();
    supabase.auth.getUser().then(({ data }) => {
      if (!data.user) { router.push('/auth/login'); return; }
      setUser({ id: data.user.id, email: data.user.email ?? '' });
    }).catch(() => router.push('/auth/login'));
  }, [router]);

  const loadData = useCallback(async () => {
    if (!user) return;
    try {
      setLoading(true);
      const orgs = await getOrganizationsForUser(user.id);
      if (orgs.length === 0) return;
      const firstOrg = orgs[0] as { id: string; name: string };
      setOrg(firstOrg);
      const [userRole, reqs] = await Promise.all([
        getUserRole(user.id, firstOrg.id).catch(() => 'employee' as UserRole),
        getVacationRequestsForOrg(firstOrg.id),
      ]);
      setRole(userRole);
      setRequests(reqs);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { loadData(); }, [loadData]);

  // Stats
  const myRequests = requests.filter(r => r.user_id === user?.id);
  const pending  = requests.filter(r => r.status === 'pending');
  const approved = requests.filter(r => r.status === 'approved' &&
    (role === 'admin' || role === 'approver' || r.user_id === user?.id));
  const upcoming = approved.filter(r => isFuture(parseISO(r.from)));

  // Approved days this year
  const thisYear = new Date().getFullYear();
  const approvedDaysThisYear = myRequests
    .filter(r => r.status === 'approved' && parseISO(r.from).getFullYear() === thisYear)
    .reduce((sum, r) => sum + differenceInCalendarDays(parseISO(r.to), parseISO(r.from)) + 1, 0);

  const recentRequests = (canApprove(role) ? requests : myRequests).slice(0, 5);

  const statusConfig = {
    pending:  { label: 'Ausstehend', color: 'badge-pending',  Icon: Clock },
    approved: { label: 'Genehmigt',  color: 'badge-approved', Icon: CheckCircle },
    rejected: { label: 'Abgelehnt', color: 'badge-rejected',  Icon: XCircle },
  };

  if (!user) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-sm" style={{ color: 'var(--text-muted)' }}>Lade...</div>
      </div>
    );
  }

  return (
    <div className="p-6 md:p-8 w-full animate-fade-in">
      {/* ─── Page Header ─────────────────────────────────── */}
      <div className="flex items-start justify-between mb-8 flex-wrap gap-4">
        <div>
          <h1 className="text-2xl font-black tracking-tight" style={{ color: 'var(--text-base)' }}>
            Willkommen zurück 👋
          </h1>
          <p className="text-sm mt-1" style={{ color: 'var(--text-muted)' }}>
            {org ? (
              <>Organisation: <span className="font-semibold" style={{ color: 'var(--text-base)' }}>{org.name}</span></>
            ) : 'Kein Unternehmen ausgewählt'}
            {role && (
              <span className={`ml-2 badge ${role === 'admin' ? 'role-admin' : role === 'approver' ? 'role-approver' : 'role-employee'}`}>
                {ROLE_LABELS[role]}
              </span>
            )}
          </p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <div className="flex items-center bg-[var(--bg-elevated)] p-1 rounded-xl border" style={{ borderColor: 'var(--border)' }}>
            <button
              onClick={() => setViewMode('list')}
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
              title="Listenansicht"
            >
              <List size={14} />
            </button>
            <button
              onClick={() => setViewMode('grid')}
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
              title="Rasteransicht"
            >
              <LayoutGrid size={14} />
            </button>
          </div>
          <Link href="/dashboard/calendar" className="btn-secondary">
            <CalendarDays size={14} />
            Kalender
          </Link>
          <Link href="/dashboard/requests" className="btn-primary">
            <Plus size={14} />
            Neuer Antrag
          </Link>
        </div>
      </div>

      {/* ─── KPI Cards ────────────────────────────────────── */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {/* Ausstehend */}
        <div className="kpi-card animate-fade-in-d1">
          <div className="flex items-start justify-between mb-3">
            <div className="p-2 rounded-xl" style={{ background: 'var(--warning-light)' }}>
              <Clock size={18} style={{ color: 'var(--warning)' }} />
            </div>
            {pending.length > 0 && (
              <span className="text-[10px] font-bold text-white bg-[var(--warning)] px-1.5 py-0.5 rounded-full">
                Neu
              </span>
            )}
          </div>
          <p className="text-3xl font-black mb-1" style={{ color: 'var(--text-base)' }}>
            {pending.length}
          </p>
          <p className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
            {canApprove(role) ? 'Ausstehende Anträge' : 'Meine ausstehenden'}
          </p>
        </div>

        {/* Genehmigt */}
        <div className="kpi-card animate-fade-in-d2">
          <div className="flex items-start justify-between mb-3">
            <div className="p-2 rounded-xl" style={{ background: 'var(--success-light)' }}>
              <CheckCircle size={18} style={{ color: 'var(--success)' }} />
            </div>
          </div>
          <p className="text-3xl font-black mb-1" style={{ color: 'var(--text-base)' }}>
            {approved.length}
          </p>
          <p className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
            Genehmigte Anträge
          </p>
        </div>

        {/* Urlaubstage genutzt */}
        <div className="kpi-card animate-fade-in-d3">
          <div className="flex items-start justify-between mb-3">
            <div className="p-2 rounded-xl" style={{ background: 'var(--primary-light)' }}>
              <TrendingUp size={18} style={{ color: 'var(--primary)' }} />
            </div>
          </div>
          <p className="text-3xl font-black mb-1" style={{ color: 'var(--text-base)' }}>
            {approvedDaysThisYear}
          </p>
          <p className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
            Urlaubstage {new Date().getFullYear()}
          </p>
        </div>

        {/* Bevorstehende */}
        <div className="kpi-card animate-fade-in-d4">
          <div className="flex items-start justify-between mb-3">
            <div className="p-2 rounded-xl" style={{ background: 'var(--info-light)' }}>
              <CalendarDays size={18} style={{ color: 'var(--info)' }} />
            </div>
          </div>
          <p className="text-3xl font-black mb-1" style={{ color: 'var(--text-base)' }}>
            {upcoming.length}
          </p>
          <p className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
            Bevorstehende Urlaube
          </p>
        </div>
      </div>

      {/* ─── Content Grid ─────────────────────────────────── */}
      <div className="grid lg:grid-cols-3 gap-6">
        {/* Aktuelle Anträge */}
        <div className="lg:col-span-2 card p-5 animate-fade-in-d1">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h2 className="text-sm font-bold" style={{ color: 'var(--text-base)' }}>
                {canApprove(role) ? 'Alle Anträge' : 'Meine Anträge'}
              </h2>
              <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
                Aktuelle Urlaubsanträge
              </p>
            </div>
            <Link href="/dashboard/requests" className="btn-ghost text-xs">
              Alle anzeigen <ArrowRight size={12} />
            </Link>
          </div>

          {loading ? (
            <div className="space-y-2">
              {[1,2,3].map(i => <div key={i} className="skeleton h-16 rounded-xl" />)}
            </div>
          ) : recentRequests.length === 0 ? (
            <div className="text-center py-10">
              <ClipboardList size={32} className="mx-auto mb-3 opacity-20" />
