        </div>

        {/* Seitenleiste */}
        <div className="flex flex-col gap-4">
          {/* Quick Actions */}
          <div className="card p-5 animate-fade-in-d3">
            <h2 className="text-sm font-bold mb-3" style={{ color: 'var(--text-base)' }}>
