              {canApprove(role) && (
                <Link href="/dashboard/requests?filter=pending" className="btn-secondary w-full justify-center" style={{ borderColor: 'rgba(245,158,11,0.3)', color: 'var(--warning)' }}>
                  <Clock size={14} /> Anträge genehmigen
