            onClick={() => setViewMode('list')}
            className={`p-1.5 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
            title="Listenansicht"
          >
            <List size={14} />
          </button>
          <button
            onClick={() => setViewMode('grid')}
            className={`p-1.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-gray-800 shadow-sm text-[var(--primary)]' : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'}`}
            title="Rasteransicht"
          >
            <LayoutGrid size={14} />
          </button>
        </div>

        {/* Search */}
        <div className="flex items-center gap-2 border rounded-xl px-3 py-1.5" style={{ borderColor: 'var(--border)', background: 'var(--bg-elevated)' }}>
          <Search size={12} style={{ color: 'var(--text-muted)' }} />
          <input
            type="text"
            placeholder="Suchen..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="bg-transparent border-none outline-none text-xs w-28"
            style={{ color: 'var(--text-base)' }}
          />
        </div>
      </div>

      {/* Requests Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="p-8 space-y-3">
            {[1,2,3].map(i => <div key={i} className="skeleton h-16 rounded-xl" />)}
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-16">
            <ClipboardList size={40} className="mx-auto mb-4 opacity-20" />
            <p className="text-sm font-medium" style={{ color: 'var(--text-muted)' }}>
              {statusFilter === 'all' ? 'Noch keine Anträge vorhanden' : `Keine ${statusConfig[statusFilter].label.toLowerCase()} Anträge`}
            </p>
            <button onClick={() => setShowWizard(true)} className="btn-primary mt-4 inline-flex">
              <Plus size={13} /> Ersten Antrag stellen
            </button>
          </div>
        ) : viewMode === 'list' ? (
          <table className="data-table">
            <thead>
              <tr>
                <th>Zeitraum</th>
                <th>Dauer</th>
                <th>Grund</th>
                <th>Status</th>
                {canApprove(role) && <th>Aktionen</th>}
                <th></th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(r => (
                <tr key={r.id}>
                  <td>
                    <div style={{ color: 'var(--text-base)' }} className="font-semibold text-sm">
                      {format(parseISO(r.from), 'dd.MM.yyyy', { locale: de })}
                    </div>
                    <div style={{ color: 'var(--text-muted)' }} className="text-xs">
                      – {format(parseISO(r.to), 'dd.MM.yyyy', { locale: de })}
                    </div>
                  </td>
                  <td>
                    <span className="badge badge-primary">
                      {differenceInCalendarDays(parseISO(r.to), parseISO(r.from)) + 1} Tage
                    </span>
                  </td>
                  <td>
                    <span className="text-sm truncate max-w-[180px] block" style={{ color: 'var(--text-muted)' }}>
                      {r.reason || '–'}
                    </span>
                  </td>
                  <td>
                    <span className={`badge ${
                      r.status === 'approved' ? 'badge-approved' :
                      r.status === 'rejected' ? 'badge-rejected' : 'badge-pending'
                    }`}>
                      {r.status === 'approved' ? 'Genehmigt' : r.status === 'rejected' ? 'Abgelehnt' : 'Ausstehend'}
                    </span>
                  </td>
                  {canApprove(role) && (
                    <td>
                      {r.status === 'pending' && (
                        <div className="flex items-center gap-1.5">
                          <button
                            onClick={() => handleStatus(r.id, 'approved')}
                            disabled={actionId === r.id}
                            className="flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-semibold transition-all disabled:opacity-50"
                            style={{ background: 'var(--success-light)', color: 'var(--success)' }}
                          >
                            {actionId === r.id ? <Loader size={10} className="animate-spin" /> : <CheckCircle size={10} />}
                            Genehmigen
                          </button>
                          <button
                            onClick={() => handleStatus(r.id, 'rejected')}
                            disabled={actionId === r.id}
                            className="flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-semibold transition-all disabled:opacity-50"
                            style={{ background: 'var(--danger-light)', color: 'var(--danger)' }}
                          >
                            <XCircle size={10} />
                            Ablehnen
                          </button>
                        </div>
                      )}
                    </td>
                  )}
                  <td>
                    <Link href={`/dashboard/requests/${r.id}`} className="btn-ghost p-1.5" title="Details">
                      <Eye size={14} />
                    </Link>
                  </td>
