                <div className="flex justify-between items-start">
                  <div>
                    <span className={`badge mb-2 inline-block ${
                      r.status === 'approved' ? 'badge-approved' :
                      r.status === 'rejected' ? 'badge-rejected' : 'badge-pending'
                    }`}>
                      {r.status === 'approved' ? 'Genehmigt' : r.status === 'rejected' ? 'Abgelehnt' : 'Ausstehend'}
                    </span>
                    <div className="text-sm font-bold" style={{ color: 'var(--text-base)' }}>
                      {format(parseISO(r.from), 'dd.MM')} – {format(parseISO(r.to), 'dd.MM.yyyy')}
