        )}
      </div>

      {/* Wizard Modal */}
      {showWizard && user && (
        <WizardVacationRequest
          userId={user.id}
          orgId={org?.id || ''}
          userEmail={user.email}
          orgName={org?.name || 'Standard Organisation'}
          onClose={() => setShowWizard(false)}
          onSuccess={() => { setShowWizard(false); loadData(); }}
