'use client';
import { useState } from 'react';
import {
  X, RefreshCw, CheckCircle, ExternalLink, Calendar,
  AlertCircle, ChevronRight, Mail
} from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { saveOAuthSettings, getOAuthSettings, fetchExternalEvents, importCalendarEvents, ExternalCalendarEvent } from '@/lib/calendarSync';

interface CalendarSyncProps {
  orgId: string;
  userId: string;
  onClose: () => void;
  onSynced: () => void;
}

type Provider = 'outlook' | 'google';
type Step = 'choose' | 'connect' | 'select' | 'done';

export default function CalendarSync({ orgId, userId, onClose, onSynced }: CalendarSyncProps) {
  const [step, setStep] = useState<Step>('choose');
  const [provider, setProvider] = useState<Provider | null>(null);
  const [email, setEmail] = useState('');
  const [token, setToken] = useState('');
  const [syncing, setSyncing] = useState(false);
  const [error, setError] = useState('');
  const [connected, setConnected] = useState(false);
  const [importAll, setImportAll] = useState(true);
  const [events, setEvents] = useState<{ id: string; title: string; start: string; end: string; selected: boolean }[]>([]);

  const handleChooseProvider = (p: Provider) => {
    setProvider(p);
    setStep('connect');
  };

  const handleConnect = async () => {
    if (!email.trim()) { setError('Bitte E-Mail-Adresse eingeben'); return; }
    if (!token.trim()) { setError('Bitte Token / App-Passwort eingeben'); return; }
    setError('');
    setSyncing(true);

    try {
      // Save credentials securely in user_settings JSONB
      await saveOAuthSettings(userId, orgId, provider!, email, token);

      // Fetch events using refined library
      const fetchedEvents = await fetchExternalEvents(provider!, token);

      setEvents(fetchedEvents.map(ev => ({
        id: ev.id,
        title: ev.title,
        start: ev.start,
        end: ev.end,
        selected: true
      })));

      setConnected(true);
      setStep('select');
    } catch (err) {
      setError((err as Error).message || 'Verbindung fehlgeschlagen');
    } finally {
      setSyncing(false);
    }
  };

  const handleImport = async () => {
    setSyncing(true);
    setError('');
    try {
      const toImport = importAll ? events : events.filter(e => e.selected);

      if (toImport.length === 0) {
        setError('Bitte mindestens einen Termin auswählen.');
        setSyncing(false);
        return;
      }

      await importCalendarEvents(toImport.map(ev => ({
        userId,
        orgId,
        provider: provider!,
        externalId: ev.id,
        title: ev.title,
        startDate: ev.start,
        endDate: ev.end,
        allDay: true // Standard for simplicity
      })));

      setStep('done');
      onSynced();
    } catch (err) {
      setError((err as Error).message || 'Import fehlgeschlagen');
    } finally {
      setSyncing(false);
    }
  };

  const toggleEvent = (id: string) => {
    setEvents(prev => prev.map(e => e.id === id ? { ...e, selected: !e.selected } : e));
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative w-full max-w-md card p-6 animate-fade-in" style={{ zIndex: 51 }}>
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-lg font-bold" style={{ color: 'var(--text-base)' }}>
              Kalender synchronisieren
            </h2>
            <p className="text-xs mt-0.5" style={{ color: 'var(--text-muted)' }}>
              Outlook oder Google Kalender verbinden
            </p>
          </div>
          <button onClick={onClose} className="btn-ghost p-1.5"><X size={16} /></button>
        </div>

        {/* Step Indicators */}
        <div className="flex items-center gap-1 mb-6">
          {(['choose', 'connect', 'select', 'done'] as Step[]).map((s, i) => (
            <div key={s} className="flex items-center gap-1 flex-1">
              <div className={`wizard-step-dot text-[11px] ${
                step === s ? 'active' : (['choose', 'connect', 'select', 'done'].indexOf(step) > i) ? 'done' : 'inactive'
              }`}>
                {['choose', 'connect', 'select', 'done'].indexOf(step) > i ? '✓' : i + 1}
              </div>
              {i < 3 && <div className={`flex-1 h-px ${['choose', 'connect', 'select', 'done'].indexOf(step) > i ? 'bg-[var(--success)]' : 'bg-[var(--border)]'}`} />}
            </div>
          ))}
        </div>

        {/* Step: Choose Provider */}
        {step === 'choose' && (
          <div className="space-y-3">
            <p className="text-sm mb-4" style={{ color: 'var(--text-muted)' }}>
              Wähle deinen Kalender-Anbieter:
            </p>
            <button
              onClick={() => handleChooseProvider('outlook')}
              className="oauth-btn w-full"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                <rect width="24" height="24" rx="4" fill="#0078d4"/>
                <text x="5" y="17" fontSize="14" fill="white" fontWeight="bold">O</text>
              </svg>
              <span>Mit Outlook verbinden</span>
              <ChevronRight size={14} className="ml-auto" />
            </button>
            <button
              onClick={() => handleChooseProvider('google')}
              className="oauth-btn w-full"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
              <span>Mit Google verbinden</span>
              <ChevronRight size={14} className="ml-auto" />
            </button>

            <div className="p-3 rounded-xl mt-4 flex items-start gap-2" style={{ background: 'var(--primary-light)', borderLeft: '3px solid var(--primary)' }}>
              <AlertCircle size={14} style={{ color: 'var(--primary)' }} className="shrink-0 mt-0.5" />
              <p className="text-xs" style={{ color: 'var(--primary)' }}>
                Die Verbindung nutzt deine gespeicherten Zugangsdaten. Richten Sie OAuth in den App-Einstellungen ein.
              </p>
            </div>
          </div>
        )}

        {/* Step: Connect (enter credentials) */}
        {step === 'connect' && (
          <div className="space-y-4">
            <p className="text-sm font-semibold" style={{ color: 'var(--text-base)' }}>
              {provider === 'outlook' ? '📧 Outlook' : '📅 Google'} verbinden
            </p>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>
                {provider === 'outlook' ? 'Microsoft-Konto E-Mail' : 'Google-Konto E-Mail'}
              </label>
              <input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="name@firma.de"
                className="w-full px-3 py-2.5 rounded-lg border text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>
                {provider === 'outlook' ? 'Access Token (aus Azure App)' : 'OAuth Token (aus Google Console)'}
              </label>
              <input
                type="password"
                value={token}
                onChange={e => setToken(e.target.value)}
                placeholder="Token eingeben..."
                className="w-full px-3 py-2.5 rounded-lg border text-sm"
              />
              <p className="text-[10px] mt-1" style={{ color: 'var(--text-subtle)' }}>
                Token in Einstellungen → OAuth hinterlegen und hier eintragen
              </p>
            </div>
            {error && <div className="text-xs p-2.5 rounded-lg" style={{ background: 'var(--danger-light)', color: 'var(--danger)' }}>{error}</div>}
            <div className="flex gap-2 pt-2">
              <button onClick={() => setStep('choose')} className="btn-secondary flex-1">Zurück</button>
              <button onClick={handleConnect} disabled={syncing} className="btn-primary flex-1">
                {syncing ? <RefreshCw size={13} className="animate-spin" /> : null}
                {syncing ? 'Verbinde...' : 'Verbinden'}
              </button>
            </div>
          </div>
        )}

        {/* Step: Select Events */}
        {step === 'select' && (
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <CheckCircle size={16} style={{ color: 'var(--success)' }} />
              <p className="text-sm font-semibold" style={{ color: 'var(--success)' }}>
                Verbunden! {events.length} Termine gefunden
              </p>
            </div>

            <div className="flex items-center gap-2 p-3 rounded-xl" style={{ background: 'var(--bg-elevated)' }}>
              <input
                type="checkbox"
                id="importAll"
                checked={importAll}
                onChange={e => setImportAll(e.target.checked)}
                className="w-4 h-4 rounded"
              />
              <label htmlFor="importAll" className="text-sm font-medium" style={{ color: 'var(--text-base)' }}>
                Alle Termine importieren
              </label>
            </div>

            {!importAll && (
              <div className="space-y-2 max-h-48 overflow-y-auto">
                {events.map(ev => (
                  <div key={ev.id} className="flex items-center gap-2 p-2.5 rounded-xl" style={{ background: 'var(--bg-elevated)' }}>
                    <input
                      type="checkbox"
                      checked={ev.selected}
                      onChange={() => toggleEvent(ev.id)}
                      className="w-4 h-4 rounded"
                    />
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-semibold truncate" style={{ color: 'var(--text-base)' }}>{ev.title}</p>
                      <p className="text-[10px]" style={{ color: 'var(--text-muted)' }}>
                        {ev.start} {ev.start !== ev.end ? `– ${ev.end}` : ''}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {error && <div className="text-xs p-2.5 rounded-lg" style={{ background: 'var(--danger-light)', color: 'var(--danger)' }}>{error}</div>}
            <div className="flex gap-2">
              <button onClick={() => setStep('connect')} className="btn-secondary flex-1">Zurück</button>
              <button onClick={handleImport} disabled={syncing} className="btn-primary flex-1">
                {syncing ? <RefreshCw size={13} className="animate-spin" /> : null}
                {syncing ? 'Importiere...' : 'Importieren'}
              </button>
            </div>
          </div>
        )}

        {/* Step: Done */}
        {step === 'done' && (
          <div className="text-center py-4">
            <div className="w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4" style={{ background: 'var(--success-light)' }}>
              <CheckCircle size={32} style={{ color: 'var(--success)' }} />
            </div>
            <p className="text-lg font-bold mb-2" style={{ color: 'var(--text-base)' }}>Synchronisiert!</p>
            <p className="text-sm mb-6" style={{ color: 'var(--text-muted)' }}>
              Deine Termine wurden erfolgreich importiert.
            </p>
            <button onClick={onClose} className="btn-primary">
              Kalender anzeigen
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import { getOrganizationsForUser } from '@/lib/organization';
import { getUserRole } from '@/lib/roles';
import { useEffect, useState } from 'react';
import CreateOrganization from './CreateOrganization';
import { Plus } from 'lucide-react';

export default function OrganizationSwitcher({ userId, onOrgChange }: { userId: string, onOrgChange: (orgId: string, role: string) => void }) {
  const [orgs, setOrgs] = useState<{ id: string; name: string }[]>([]);
  const [selectedOrg, setSelectedOrg] = useState<string>('');
  const [showCreate, setShowCreate] = useState(false);

  useEffect(() => {
    loadOrgs();
  }, [userId]);

  const loadOrgs = () => {
    getOrganizationsForUser(userId).then(data => {
      const filtered = (data || []).filter((o): o is { id: string; name: string } => o !== null);
      setOrgs(filtered);
      if (filtered.length > 0 && !selectedOrg) {
        setSelectedOrg(filtered[0].id);
      }
    });
  };

  useEffect(() => {
    if (selectedOrg) {
      getUserRole(userId, selectedOrg).then(role => {
        onOrgChange(selectedOrg, role);
      });
    }
  }, [selectedOrg, userId, onOrgChange]);

  const handleOrgCreated = (newOrg: { id: string; name: string }) => {
    setOrgs(prev => [...prev, newOrg]);
    setSelectedOrg(newOrg.id);
    setShowCreate(false);
  };

  return (
    <div className="mb-4">
      <div className="flex items-center justify-between mb-2">
        <label className="font-semibold text-gray-200">Organisation</label>
        <button 
          onClick={() => setShowCreate(prev => !prev)}
          className="text-blue-500 hover:text-blue-400 text-xs flex items-center gap-1.5 transition-colors font-medium border border-blue-500/20 bg-blue-500/10 px-2 py-1 rounded-md"
        >
          <Plus size={12} />
          {showCreate ? 'Abbrechen' : 'Neu'}
        </button>
      </div>

      {orgs.length === 0 ? (
        <div className="text-sm text-gray-500 mb-2 italic">Noch keine Organisationen. Starten Sie durch Erstellen einer neuen.</div>
      ) : (
        <div className="flex items-center">
          <select
            className="w-full border border-gray-700 rounded-lg px-3 py-2 bg-gray-950 text-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-600 focus:border-transparent transition-all"
            value={selectedOrg}
            onChange={e => setSelectedOrg(e.target.value)}
          >
            {orgs.map(org => (
              <option key={org.id} value={org.id}>{org.name}</option>
            ))}
          </select>
        </div>
      )}

      {showCreate && (
        <CreateOrganization userId={userId} onCreated={handleOrgCreated} />
      )}
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { createClient } from '@/lib/supabase/client';
import { toggleUserRoleAction } from '@/lib/actions/debugActions';
import { CheckCircle, AlertCircle, Loader2 } from 'lucide-react';

/**
 * SchemaRoleSwitcher - 1:1 Visuell exakt wie TeamRadar.
 * Positioniert am Ende der Sidebar vor dem Theme-Switcher.
 */
export default function SchemaRoleSwitcher() {
  const [currentSchema, setCurrentSchema] = useState('');
  const [currentRole, setCurrentRole] = useState<string>('');
  const [mounted, setMounted] = useState(false);
  const [switching, setSwitching] = useState<string | null>(null);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  useEffect(() => {
    setMounted(true);
    const schema = process.env.NEXT_PUBLIC_SCHEMA || 'away-dev';
    setCurrentSchema(schema);

    const checkRole = async () => {
      try {
        const supabase = createClient();
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        const { data } = await supabase
          .from('user_roles')
          .select('role')
          .eq('user_id', user.id)
          .maybeSingle();

        setCurrentRole(data?.role || 'employee');
      } catch (err) {
        console.error('Debug Role Check failed:', err);
      }
    };

    checkRole();
  }, []);

  const handleToggle = async (newRole: string) => {
    if (newRole === currentRole || switching) return;
    setSwitching(newRole);
    setMessage(null);
    try {
      // Server Action mit Service Role Key
      const result = await toggleUserRoleAction(newRole);
      if (result.success) {
        setCurrentRole(result.newRole);
        setMessage({ type: 'success', text: `Rolle zu ${result.newRole} gewechselt.` });
        // Refresh nach Erfolg
        setTimeout(() => window.location.reload(), 1200);
      }
    } catch (err: any) {
      console.error('Toggle Error:', err);
      setMessage({ type: 'error', text: err.message || 'Fehler beim Wechsel' });
    } finally {
      setSwitching(null);
    }
  };

  if (!mounted) return null;

  const roles = [
    { id: 'admin', label: 'Admin' },
    { id: 'cio', label: 'CIO' },
    { id: 'department_lead', label: 'Ltg.' },
    { id: 'employee', label: 'Mitarb.' },
  ];

  return (
    <div className="mb-2 px-3 flex flex-col gap-2">
      {/* Toast-Nachricht (Schwebend über dem Switcher) */}
      {message && (
        <div className={`fixed bottom-24 left-6 right-6 md:right-auto md:w-[230px] px-3 py-2 rounded-xl text-[10px] font-bold shadow-2xl border z-[99999] animate-in slide-in-from-bottom-4 fade-in duration-300 ${
          message.type === 'success' 
            ? 'bg-emerald-500 text-white border-emerald-400' 
            : 'bg-rose-500 text-white border-rose-400 font-mono italic text-[9px]'
        }`}>
          <div className="flex items-center gap-2">
            {message.type === 'success' ? <CheckCircle size={12} /> : <AlertCircle size={12} />}
            <span className="truncate">{message.text}</span>
          </div>
        </div>
      )}

      {/* TeamRadar 1:1 Design Box */}
      <div className="p-0.5 rounded-xl bg-blue-500/5 border border-blue-500/10 flex flex-col gap-1 p-2">
        <div className="flex items-center justify-between px-1 mb-1">
          <div className="text-[8px] font-black text-blue-500/50 uppercase tracking-[0.2em]">Dev: Role Switch</div>
          <div className="text-[7px] font-mono text-blue-500/30 uppercase opacity-50">{currentSchema}</div>
        </div>

        <div className="grid grid-cols-2 gap-1">
          {roles.map((r) => (
            <button
              key={r.id}
              onClick={() => handleToggle(r.id)}
              disabled={!!switching}
              className={`py-1.5 rounded text-[10px] font-bold transition-all border-none cursor-pointer flex items-center justify-center gap-1 ${
                currentRole === r.id 
                  ? 'bg-blue-500 text-white shadow-sm' 
                  : 'text-blue-500/40 hover:bg-blue-500/10 hover:text-blue-500/60'
              } ${switching ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              {switching === r.id && <Loader2 size={10} className="animate-spin" />}
              {r.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import { createClient } from '@/lib/supabase/client';
import {
  X, ChevronRight, ChevronLeft, Upload, FileText, Calendar,
  CheckCircle, Loader, Mail, AlertCircle, Download, Eye, File as FileIcon,
  Plus, Trash2
} from 'lucide-react';
import { generatePDF, generateExcel, generateWord, DocumentData } from '@/lib/documentGenerator';
import { differenceInBusinessDays, parseISO } from 'date-fns';
import Modal from './ui/Modal';

interface WizardProps {
  userId: string;
  orgId: string;
  userEmail: string;
  orgName: string;
  onClose: () => void;
  onSuccess: () => void;
}

type Step = 1 | 2 | 3 | 4;

interface Template {
  id: string;
  name: string;
  type: 'pdf' | 'docx' | 'xlsx';
  storage_path: string;
}

interface VacationType {
  id: string;
  label: string;
  checked: boolean;
}

export default function WizardVacationRequest({ userId, orgId, userEmail, orgName, onClose, onSuccess }: WizardProps) {
  const [step, setStep] = useState<Step>(1);
  const [templates, setTemplates] = useState<Template[]>([]);
  const [selectedTemplate, setSelectedTemplate] = useState<Template | null>(null);
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);

  // Alle 9 Felder wiederherstellen
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [employeeId, setEmployeeId] = useState('');
  const [documentId, setDocumentId] = useState('');
  const [vacationDays, setVacationDays] = useState<number>(0);
  const [vacationTypes, setVacationTypes] = useState<VacationType[]>([
    { id: 'bezahlt', label: 'Bezahlter Urlaub', checked: true },
    { id: 'unbezahlt', label: 'Unbezahlter Urlaub', checked: false },
    { id: 'ausgleich', label: 'Freizeitausgleich', checked: false },
    { id: 'sonder', label: 'Sonderurlaub', checked: false }
  ]);
  const [newTypeName, setNewTypeName] = useState('');
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [reason, setReason] = useState('');
  const [location, setLocation] = useState('');
  const [signedAt, setSignedAt] = useState(new Date().toISOString().split('T')[0]);
  const [employeeSignature, setEmployeeSignature] = useState<string | null>(null);
  const [approverSignature, setApproverSignature] = useState<string | null>(null);

  // Hilfsfelder
  const [deputy, setDeputy] = useState('');
  const [notes, setNotes] = useState('');
  const [sendMail, setSendMail] = useState(false);
  const [approverEmail, setApproverEmail] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [generating, setGenerating] = useState(false);

  useEffect(() => {
    const supabase = createClient();
    if (orgId) {
      supabase.from('document_templates').select('*').eq('organization_id', orgId)
        .then(({ data }) => setTemplates((data as Template[]) || []));
    }
    supabase.auth.getUser().then(({ data }) => {
      if (data.user) {
        setFirstName(data.user.user_metadata.first_name || '');
        setLastName(data.user.user_metadata.last_name || '');
      }
    });
  }, [orgId]);

  useEffect(() => {
    if (from && to) {
      try {
        const days = differenceInBusinessDays(parseISO(to), parseISO(from)) + 1;
        setVacationDays(days > 0 ? days : 0);
      } catch { setVacationDays(0); }
    }
  }, [from, to]);

  const addVacationType = () => {
    if (!newTypeName.trim()) return;
    setVacationTypes([...vacationTypes, { id: Date.now().toString(), label: newTypeName, checked: false }]);
    setNewTypeName('');
  };
  const removeVacationType = (id: string) => setVacationTypes(vacationTypes.filter(t => t.id !== id));
  const toggleVacationType = (id: string) => setVacationTypes(vacationTypes.map(t => t.id === id ? { ...t, checked: !t.checked } : t));

  const handleFileUpload = (file: File) => {
    const ext = file.name.split('.').pop()?.toLowerCase();
    setUploadedFile(file);
    setSelectedTemplate({ id: 'custom-'+Date.now(), name: file.name.split('.')[0], type: ext as any, storage_path: '' });
  };

  const generateDocumentBlob = async (): Promise<{ blob: Blob; ext: string } | null> => {
    try {
      setGenerating(true);
      let bytes: ArrayBuffer | undefined = undefined;
      let type: 'pdf' | 'docx' | 'xlsx' = 'pdf';

      if (uploadedFile) {
        bytes = await uploadedFile.arrayBuffer();
        type = uploadedFile.name.split('.').pop()?.toLowerCase() as any;
      } else if (selectedTemplate?.storage_path) {
        const supabase = createClient();
        const { data: fileData, error: downloadError } = await supabase.storage
          .from('templates').download(selectedTemplate.storage_path);
        if (downloadError) throw downloadError;
        bytes = await fileData.arrayBuffer();
        type = selectedTemplate.type;
      }

      const typesObj = vacationTypes.reduce((acc, t) => ({ ...acc, [t.label]: t.checked }), {});
      const docData: DocumentData = {
        from, to, reason, deputy, notes, userEmail, orgName: orgName || 'Haupt-Organisation',
        date: new Date().toLocaleDateString('de-DE'),
        customFields: { firstName, lastName, employeeId, documentId, vacationDays: vacationDays.toString(), location, signedAt, ...typesObj }
      };

      let blob: Blob;
      if (type === 'xlsx') blob = await generateExcel(docData, bytes);
      else if (type === 'docx') blob = await generateWord(docData, bytes!);
      else blob = await generatePDF(docData, bytes);

      return { blob, ext: type };
    } catch (err) { console.error(err); return null; } finally { setGenerating(false); }
  };

  const handleSubmit = async () => {
    if (!from || !to) { setError('Bitte Von- und Bis-Datum angeben'); return; }
    setError('');
    setSubmitting(true);
    try {
      const supabase = createClient();
      const { data, error: insertError } = await supabase.from('vacation_requests').insert([{
        user_id: userId, organization_id: orgId, from, to, reason, status: 'pending',
        template_fields: { deputy, notes, firstName, lastName, employeeId, documentId, vacationDays, vacationTypes, location, signedAt },
      }]).select('id').single();

      if (insertError) throw insertError;

      // Signatur-Upload
      if (employeeSignature || approverSignature) {
        const uploadSig = async (sig: string, t: string) => {
          const res = await fetch(sig);
          const blob = await res.blob();
          await supabase.storage.from('signatures').upload(`${data.id}/${t}.png`, blob, { upsert: true });
        };
        if (employeeSignature) await uploadSig(employeeSignature, 'employee');
        if (approverSignature) await uploadSig(approverSignature, 'approver');
      }

      // Dokumenten-Upload
      const result = await generateDocumentBlob();
      if (result && result.ext === 'pdf') {
        await supabase.storage.from('vacation-documents').upload(`vacation-${data.id}.pdf`, result.blob, { contentType: 'application/pdf', upsert: true });
      }

      setStep(4);
    } catch (err: any) { setError(err.message); } finally { setSubmitting(false); }
  };

  const footer = step < 4 && (
    <div className="flex gap-3">
      {step > 1 && (
        <button onClick={() => setStep((step - 1) as Step)} className="flex-1 py-4 px-6 rounded-2xl bg-[var(--bg-elevated)] text-[var(--text-base)] font-black text-xs uppercase tracking-[0.2em] border-2 border-[var(--border)] flex items-center justify-center gap-2 hover:bg-[var(--bg-surface)]">
          <ChevronLeft size={16} /> Zurück
        </button>
      )}
      <button 
        onClick={() => step === 3 ? handleSubmit() : setStep((step + 1) as Step)}
        disabled={submitting || (step === 1 && !selectedTemplate && !uploadedFile)}
        className="flex-[2] py-4 px-6 rounded-2xl bg-[var(--primary)] text-white font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-2 shadow-lg hover:scale-[1.02] active:scale-[0.98] transition-all"
      >
        {submitting ? <Loader size={16} className="animate-spin" /> : (step === 3 ? 'Einreichen' : 'Weiter')}
        {step < 3 && <ChevronRight size={16} />}
      </button>
    </div>
  );

  return (
    <Modal isOpen={true} onClose={onClose} title="Neuer Urlaubsantrag" subtitle={`Schritt ${step} von 4`} footer={footer} maxWidth="max-w-2xl">
      <div className="space-y-8 py-2">
        {/* Step Indicators */}
        <div className="flex items-center px-4">
          {[1,2,3,4].map((i) => (
            <div key={i} className="flex items-center flex-1">
              <div className="flex flex-col items-center gap-1.5 focus:outline-none">
                <div className={`wizard-step-dot !w-8 !h-8 !text-[11px] ${step === i ? 'active' : step > i ? 'done' : 'inactive'}`}>
                  {step > i ? '✓' : i}
                </div>
                <span className="text-[9px] font-black uppercase tracking-widest opacity-60">
                  {['Vorlage', 'Details', 'Überprüfen', 'Fertig'][i-1]}
                </span>
              </div>
              {i < 4 && <div className={`flex-1 h-[2px] mx-2 mt-[-16px] transition-all duration-500 ${step > i ? 'bg-[var(--success)] shadow-[0_0_8px_rgba(34,197,94,0.3)]' : 'bg-[var(--border)]'}`} />}
            </div>
          ))}
        </div>

        {step === 1 && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-in fade-in slide-in-from-right-4">
             {templates.map(t => (
               <button key={t.id} onClick={() => { setSelectedTemplate(t); setStep(2); }} className={`p-5 rounded-2xl border-2 text-left transition-all ${selectedTemplate?.id === t.id ? 'border-[var(--primary)] bg-[var(--primary-light)]' : 'border-[var(--border)] bg-[var(--bg-elevated)] hover:border-[var(--text-muted)]'}`}>
                 <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-xl bg-indigo-500/10 flex items-center justify-center text-indigo-500"><FileIcon size={20} /></div>
                   <div className="flex-1 min-w-0"><p className="text-sm font-black truncate">{t.name}</p><p className="text-[9px] font-black uppercase tracking-widest opacity-50">{t.type}</p></div>
                 </div>
               </button>
             ))}
             <label className="p-5 rounded-2xl border-2 border-dashed border-[var(--border)] bg-[var(--bg-elevated)] hover:bg-[var(--primary-light)] hover:border-[var(--primary)] text-center cursor-pointer transition-all">
                <Upload className="mx-auto mb-2 text-[var(--text-muted)]" size={24} />
                <p className="text-[10px] font-black uppercase tracking-widest">Eigene Vorlage</p>
                <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleFileUpload(e.target.files[0])} />
             </label>
             <button onClick={() => { setSelectedTemplate(null); setStep(2); }} className="p-5 rounded-2xl border-2 border-dashed border-[var(--border)] bg-[var(--bg-elevated)] hover:border-indigo-500/3s0 text-center transition-all md:col-span-2">
                <Plus className="mx-auto mb-2 text-indigo-500" size={24} />
                <p className="text-[10px] font-black uppercase tracking-widest">Ohne Vorlage fortfahren</p>
             </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1 decoration-blue-500">Vorname *</label><input value={firstName} onChange={e => setFirstName(e.target.value)} className="form-input-lux" /></div>
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Nachname *</label><input value={lastName} onChange={e => setLastName(e.target.value)} className="form-input-lux" /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Personalnummer</label><input value={employeeId} onChange={e => setEmployeeId(e.target.value)} className="form-input-lux" /></div>
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Belegnummer</label><input value={documentId} onChange={e => setDocumentId(e.target.value)} className="form-input-lux" /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Von *</label><input type="date" value={from} onChange={e => setFrom(e.target.value)} className="form-input-lux" /></div>
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Bis *</label><input type="date" value={to} onChange={e => setTo(e.target.value)} className="form-input-lux" /></div>
            </div>
            <div className="bg-indigo-500/5 p-4 rounded-2xl border-2 border-indigo-500/20 flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Urlaubstage (Werktage)</span>
              <input type="number" value={vacationDays} onChange={e => setVacationDays(Number(e.target.value))} className="w-16 bg-white rounded-lg px-2 py-1 text-center font-black text-sm border-2 border-indigo-500/30" />
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between"><label className="text-[10px] font-black uppercase tracking-widest opacity-60">Urlaubsart</label><div className="flex items-center gap-1.5 bg-[var(--bg-elevated)] p-1.5 rounded-xl border border-[var(--border)]"><input value={newTypeName} onChange={e => setNewTypeName(e.target.value)} placeholder="Eigene..." className="bg-transparent text-[10px] outline-none w-20 px-1 font-bold" /><button onClick={addVacationType} className="p-1.5 bg-indigo-500 text-white rounded-lg"><Plus size={12} /></button></div></div>
              <div className="grid grid-cols-2 gap-2.5">
                {vacationTypes.map(t => (
                  <div key={t.id} className="group relative">
                    <label className={`flex items-center gap-3 p-3.5 rounded-xl border-2 transition-all cursor-pointer ${t.checked ? 'border-[var(--primary)] bg-[var(--primary-light)]' : 'border-[var(--border)] bg-[var(--bg-elevated)]'}`}>
                      <input type="checkbox" checked={t.checked} onChange={() => toggleVacationType(t.id)} className="w-4 h-4 rounded text-[var(--primary)]" />
                      <span className="text-[11px] font-black truncate">{t.label}</span>
                    </label>
                    <button onClick={() => removeVacationType(t.id)} className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all"><X size={10} /></button>
                  </div>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Ort</label><input value={location} onChange={e => setLocation(e.target.value)} className="form-input-lux" /></div>
              <div className="space-y-1.5"><label className="text-[9px] font-black uppercase tracking-widest opacity-50 ml-1">Datum</label><input type="date" value={signedAt} onChange={e => setSignedAt(e.target.value)} className="form-input-lux" /></div>
            </div>

            <div className="grid grid-cols-2 gap-5">
              <div className="space-y-3">
                <label className="text-[9px] font-black uppercase tracking-widest opacity-50">Unterschrift (Mitarbeiter)</label>
                <div className="aspect-video rounded-2xl border-2 border-dashed border-[var(--border)] flex flex-col items-center justify-center bg-[var(--bg-elevated)] relative overflow-hidden transition-all hover:bg-white/5 active:scale-95">
                  {employeeSignature ? (
                    <img src={employeeSignature} className="h-full w-full object-contain p-4" alt="Signature MA" />
                  ) : (
                    <div className="flex flex-col items-center gap-2 opacity-50"><Upload size={24} /><span className="text-[8px] font-black uppercase tracking-widest">Upload PNG</span></div>
                  )}
                  <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = () => setEmployeeSignature(r.result as string); r.readAsDataURL(f); } }} />
                  {employeeSignature && <button onClick={() => setEmployeeSignature(null)} className="absolute top-2 right-2 p-1.5 bg-rose-500 text-white rounded-lg"><X size={10} /></button>}
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[9px] font-black uppercase tracking-widest opacity-50">Unterschrift (Genehmiger)</label>
                <div className="aspect-video rounded-2xl border-2 border-dashed border-[var(--border)] flex flex-col items-center justify-center bg-[var(--bg-elevated)] relative overflow-hidden transition-all hover:bg-white/5 active:scale-95">
                  {approverSignature ? (
                    <img src={approverSignature} className="h-full w-full object-contain p-4" alt="Signature Gen" />
                  ) : (
                    <div className="flex flex-col items-center gap-2 opacity-50"><Upload size={24} /><span className="text-[8px] font-black uppercase tracking-widest">Upload PNG</span></div>
                  )}
                  <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = () => setApproverSignature(r.result as string); r.readAsDataURL(f); } }} />
                  {approverSignature && <button onClick={() => setApproverSignature(null)} className="absolute top-2 right-2 p-1.5 bg-rose-500 text-white rounded-lg"><X size={10} /></button>}
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
             <div className="bg-indigo-500/5 rounded-3xl p-6 border-2 border-indigo-500/20 space-y-4">
                <div className="flex justify-between border-b border-indigo-500/10 pb-3"><span className="text-[10px] font-black uppercase opacity-60">Mitarbeiter</span><span className="text-sm font-black">{firstName} {lastName}</span></div>
                <div className="flex justify-between border-b border-indigo-500/10 pb-3"><span className="text-[10px] font-black uppercase opacity-60">Zeitraum</span><span className="text-sm font-black">{from} – {to}</span></div>
                <div className="flex justify-between border-b border-indigo-500/10 pb-3"><span className="text-[10px] font-black uppercase opacity-60">Dauer</span><span className="text-sm font-black">{vacationDays} Werktage</span></div>
                <div className="flex justify-between"><span className="text-[10px] font-black uppercase opacity-60">Grund</span><span className="text-sm font-black truncate max-w-[200px]">{reason || '–'}</span></div>
             </div>
             <button onClick={handleDownload} disabled={generating} className="w-full py-4 rounded-2xl bg-indigo-500/10 text-indigo-600 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-3 border-2 border-indigo-500/20 hover:bg-indigo-500/20 transition-all">
                {generating ? <Loader size={12} className="animate-spin" /> : <Download size={14} />} Vorschau Dokument
             </button>
          </div>
        )}

        {step === 4 && (
          <div className="text-center py-12 animate-in zoom-in-95 duration-500 overflow-hidden">
             <div className="w-24 h-24 rounded-[32px] bg-emerald-500 flex items-center justify-center mx-auto mb-6 shadow-xl shadow-emerald-500/30 rotate-3"><CheckCircle size={48} className="text-white" /></div>
             <h3 className="text-2xl font-black mb-3">Antrag eingereicht!</h3>
             <p className="text-sm font-medium opacity-60 mb-10">Dein Urlaubsantrag wurde erfolgreich erstellt.</p>
             <button onClick={onSuccess} className="w-full py-4 rounded-2xl bg-[var(--primary)] text-white font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-500/20 hover:scale-[1.02] transition-all">Fertigstellen</button>
          </div>
        )}
      </div>
    </Modal>
  );
}

'use client';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { useTheme } from '@/components/ui/ThemeProvider';
import { createClient } from '@/lib/supabase/client';
import { useEffect, useState, useCallback } from 'react';
import { getOrganizationsForUser } from '@/lib/organization';
import { getUserRole } from '@/lib/roles';
import SchemaRoleSwitcher from '@/components/SchemaRoleSwitcher';
import {
  LayoutDashboard,
  CalendarDays,
  Settings,
  X,
  Sun,
  Moon,
  ClipboardList,
  ShieldCheck,
  Mail,
  LogOut,
  Menu,
  ChevronDown,
  Plane,
  Users,
  Building2,
  Bell,
} from 'lucide-react';

type UserRole = 'admin' | 'approver' | 'employee' | null;

interface NavItem {
  href: string;
  icon: React.ElementType;
  label: string;
  exact?: boolean;
  badge?: number;
  roles?: UserRole[];
}

function SidebarContent({
  onNavigate,
  onMobileToggle,
  isMobile,
}: {
  onNavigate?: () => void;
  onMobileToggle?: () => void;
  isMobile?: boolean;
}) {
  const pathname = usePathname();
  const router = useRouter();
  const { theme, setTheme } = useTheme();
  const [userEmail, setUserEmail] = useState('');
  const [userInitial, setUserInitial] = useState('?');
  const [role, setRole] = useState<UserRole>(null);
  const [orgName, setOrgName] = useState('');
  const [pendingCount, setPendingCount] = useState(0);
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  const loadUser = useCallback(async () => {
    try {
      const supabase = createClient();
      const { data } = await supabase.auth.getUser();
      if (!data.user) return;
      const email = data.user.email ?? '';
      setUserEmail(email);
      setUserInitial(email.charAt(0).toUpperCase());

      const orgs = await getOrganizationsForUser(data.user.id);
      if (orgs.length > 0) {
        const org = orgs[0] as { id: string; name: string };
        setOrgName(org.name);
        try {
          const r = await getUserRole(data.user.id, org.id);
          setRole(r as UserRole);
        } catch { setRole('employee'); }

        // count pending requests
        const { data: pending } = await supabase
          .from('vacation_requests')
          .select('id')
          .eq('organization_id', org.id)
          .eq('status', 'pending');
        setPendingCount(pending?.length ?? 0);
      }
    } catch { /* not logged in */ }
  }, []);

  useEffect(() => { loadUser(); }, [loadUser]);

  const handleLogout = async () => {
    try {
      const supabase = createClient();
      await supabase.auth.signOut();
    } catch { /* ignore */ }
    router.push('/auth/login');
  };

  const navItems: NavItem[] = [
    { href: '/dashboard', icon: LayoutDashboard, label: 'Dashboard', exact: true },
    { href: '/dashboard/requests', icon: ClipboardList, label: 'Anträge', exact: false,
      badge: mounted && pendingCount > 0 ? pendingCount : undefined,
    },
    { href: '/dashboard/calendar', icon: CalendarDays, label: 'Kalender', exact: true },
    { href: '/dashboard/email', icon: Mail, label: 'E-Mail', exact: true },
  ];

  const adminItems: NavItem[] = [
    { href: '/dashboard/admin', icon: ShieldCheck, label: 'Administration', exact: false },
  ];

  const isActive = (href: string, exact?: boolean) =>
    exact ? pathname === href : pathname.startsWith(href);

  const NavLink = ({ item }: { item: NavItem }) => {
    const active = isActive(item.href, item.exact);
    return (
      <Link
        href={item.href}
        onClick={onNavigate}
        className={`flex items-center gap-2.5 px-3 py-2 rounded-xl text-sm font-medium no-underline transition-all duration-150 group ${
          active
            ? 'bg-[var(--primary-light)] border border-[rgba(99,102,241,0.2)]'
            : 'text-[var(--text-muted)] hover:text-[var(--text-base)] hover:bg-[var(--bg-elevated)]'
        }`}
        style={active ? { color: theme === 'dark' ? 'rgba(255,255,255,0.9)' : '#374151' } : {}}
      >
        <item.icon
          size={15}
          className={`shrink-0 transition-colors ${active ? 'text-[var(--primary)]' : 'text-current'}`}
        />
        <span className="flex-1">{item.label}</span>
        {item.badge !== undefined && item.badge > 0 && (
          <span className="text-[10px] font-bold bg-[var(--warning)] text-white px-1.5 py-0.5 rounded-full min-w-[18px] text-center">
            {item.badge}
          </span>
        )}
        {active && (
          <div className="w-1.5 h-1.5 rounded-full bg-[var(--primary)]" />
        )}
      </Link>
    );
  };

  return (
    <>
      {/* ─── Header / Logo ─────────────────────────────── */}
      <div
        className="shrink-0 flex items-center justify-between px-4 py-4 border-b"
        style={{ borderColor: 'var(--border)' }}
      >
        <div className="flex items-center gap-2.5">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-[#6366f1] to-[#8b5cf6] flex items-center justify-center shadow-lg">
            <Plane size={15} className="text-white" />
          </div>
          <div>
            <div className="text-sm font-black tracking-tight" style={{ color: 'var(--text-base)' }}>
              <span style={{ color: 'var(--primary)' }}>Away</span>
            </div>
            <div className="text-[9px] uppercase tracking-widest" style={{ color: 'var(--text-subtle)' }}>
              Urlaubsplaner
            </div>
          </div>
        </div>
        {isMobile && (
          <button
            onClick={onNavigate}
            className="btn-ghost p-1"
            aria-label="Menü schließen"
          >
            <X size={18} />
          </button>
        )}
        {!isMobile && onMobileToggle && (
          <button
            onClick={onMobileToggle}
            className="md:hidden btn-ghost p-1"
          >
            <Menu size={18} />
          </button>
        )}
      </div>

      {/* ─── Organisation ──────────────────────────────── */}
      {orgName && (
        <div className="shrink-0 mx-3 mt-3 px-3 py-2 rounded-xl flex items-center gap-2" style={{ background: 'var(--bg-elevated)' }}>
          <Building2 size={12} style={{ color: 'var(--primary)' }} className="shrink-0" />
          <span className="text-[11px] font-medium truncate" style={{ color: 'var(--text-muted)' }}>
            {orgName}
          </span>
          {role && (
            <span className={`ml-auto text-[9px] font-bold px-1.5 py-0.5 rounded-full shrink-0 badge ${
              role === 'admin' ? 'role-admin' :
              role === 'approver' ? 'role-approver' :
              'role-employee'
            }`}>
              {role === 'admin' ? 'Admin' : role === 'approver' ? 'Genehmiger' : 'Mitarbeiter'}
            </span>
          )}
        </div>
      )}

      {/* ─── Navigation ────────────────────────────────── */}
      <div className="flex-1 overflow-y-auto min-h-0">
        <div className="px-3 mt-4">
          <p className="section-label px-2 mb-2">Navigation</p>
          <nav className="flex flex-col gap-0.5">
            {navItems.map(item => <NavLink key={item.href} item={item} />)}
          </nav>
        </div>

        {/* Admin Section */}
        {(role === 'admin' || role === 'approver') && (
          <div className="px-3 mt-4">
            <p className="section-label px-2 mb-2">
              {role === 'admin' ? 'Administration' : 'Genehmigung'}
            </p>
            <nav className="flex flex-col gap-0.5">
              {role === 'admin' && adminItems.map(item => <NavLink key={item.href} item={item} />)}
              {role === 'approver' && (
                <NavLink item={{ href: '/dashboard/requests', icon: ClipboardList, label: 'Antr. genehmigen', exact: false }} />
              )}
            </nav>
          </div>
        )}
      </div>

      {/* ─── Footer with Role Switcher ─────────────────── */}
      <div className="shrink-0 border-t" style={{ borderColor: 'var(--border)' }}>

        {/* Visual 1:1 TeamRadar Switcher */}
        {mounted && process.env.NODE_ENV !== 'production' && <SchemaRoleSwitcher />}

        <div className="px-3 py-2">
          <div
            className="p-0.5 rounded-xl flex"
            style={{ background: 'var(--bg-elevated)' }}
          >
            <button
              onClick={() => setTheme('light')}
              className={`flex-1 flex items-center justify-center gap-1.5 py-1.5 rounded-lg text-[11px] font-semibold transition-all ${
                theme === 'light'
                  ? 'bg-white text-[var(--primary)] shadow-sm'
                  : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'
              }`}
            >
              <Sun size={11} />
              <span>Hell</span>
            </button>
            <button
              onClick={() => setTheme('dark')}
              className={`flex-1 flex items-center justify-center gap-1.5 py-1.5 rounded-lg text-[11px] font-semibold transition-all ${
                theme === 'dark'
                  ? 'bg-white/[0.1] text-[var(--primary)]'
                  : 'text-[var(--text-muted)] hover:text-[var(--text-base)]'
              }`}
            >
              <Moon size={11} />
              <span>Dunkel</span>
            </button>
          </div>
        </div>

        <div className="p-3">
          <div className="flex items-center gap-2.5 px-2 py-2">
            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-[var(--primary)] to-[#8b5cf6] flex items-center justify-center text-white font-bold text-xs shrink-0">
              {userInitial}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-semibold truncate" style={{ color: 'var(--text-base)' }}>
                {userEmail || 'Benutzer'}
              </p>
              <p className="text-[9px]" style={{ color: 'var(--text-subtle)' }}>Angemeldet</p>
            </div>
            <div className="flex items-center gap-1 shrink-0">
              <Link
                href="/settings"
                onClick={onNavigate}
                className={`p-1.5 rounded-lg transition-all ${
                  pathname === '/settings'
                    ? 'bg-[var(--primary-light)] text-[var(--primary)]'
                    : 'text-[var(--text-muted)] hover:text-[var(--text-base)] hover:bg-[var(--bg-elevated)]'
                }`}
                title="Einstellungen"
              >
                <Settings size={13} />
              </Link>
              <button
                onClick={handleLogout}
                className="p-1.5 rounded-lg text-[var(--text-muted)] hover:text-[var(--danger)] hover:bg-[var(--danger-light)] transition-all"
                title="Abmelden"
              >
                <LogOut size={13} />
              </button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

export function Sidebar({
  mobileOpen,
  onMobileClose,
  onMobileToggle,
}: {
  mobileOpen?: boolean;
  onMobileClose?: () => void;
  onMobileToggle?: () => void;
}) {
  return (
    <>
      <aside className="sidebar-fixed hidden md:flex flex-col">
        <SidebarContent onMobileToggle={onMobileToggle} />
      </aside>
      <aside
        className={`sidebar-fixed flex flex-col md:hidden ${mobileOpen ? 'mobile-open' : ''}`}
        style={{ zIndex: 40 }}
      >
        <SidebarContent isMobile onNavigate={onMobileClose} />
      </aside>
      {!mobileOpen && (
        <button
          onClick={onMobileToggle}
          className="fixed top-4 left-4 z-50 md:hidden p-2 rounded-xl border"
          style={{
            background: 'var(--bg-surface)',
            borderColor: 'var(--border)',
            color: 'var(--text-muted)',
          }}
          aria-label="Menü öffnen"
        >
          <Menu size={18} />
        </button>
      )}
    </>
  );
}

'use client';
import { ReactNode, useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  subtitle?: string;
  children: ReactNode;
  footer?: ReactNode;
  maxWidth?: string;
}

/**
 * Ein universelles Modal-System mit React Portals:
 * - Verhindert "Einsperren" in Containern durch Rendering am body-Ende.
 * - Nutzt das GESAMTE Fenster (fixed inset-0).
 */
export default function Modal({ isOpen, onClose, title, subtitle, children, footer, maxWidth = 'max-w-lg' }: ModalProps) {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [isOpen]);

  if (!isOpen || !mounted) return null;

  const modalContent = (
    <div className="fixed inset-0 z-[99999] flex items-center justify-center p-0 md:p-4 overflow-hidden outline-none">
      {/* Backdrop - Über das gesamte Fenster */}
      <div 
        className="absolute inset-0 bg-slate-950/80 backdrop-blur-md transition-opacity duration-300 animate-in fade-in" 
        onClick={onClose} 
      />

      {/* Modal Container */}
      <div className={`relative w-full ${maxWidth} bg-[var(--bg-surface)] md:rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-12 duration-500`} 
           style={{ maxHeight: '95vh', border: '1px solid var(--border)' }}>

        {/* Header - Fixed & Visible */}
        <div className="shrink-0 p-6 border-b border-[var(--border)] flex items-center justify-between bg-[var(--bg-surface)] z-10">
          <div>
            <h2 className="text-xl font-black tracking-tight" style={{ color: 'var(--text-base)' }}>{title}</h2>
            {subtitle && (
              <p className="text-[10px] font-black uppercase tracking-[0.2em] mt-1 opacity-50 text-[var(--primary)]">{subtitle}</p>
            )}
          </div>
          <button 
            onClick={onClose} 
            className="p-2.5 hover:bg-[var(--bg-elevated)] rounded-xl transition-all text-[var(--text-muted)] hover:text-rose-500"
            aria-label="Schließen"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content Area - Scrollable */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-8 bg-gradient-to-b from-transparent to-[var(--bg-elevated)]/5">
          <div className="animate-in fade-in duration-500">
            {children}
          </div>
        </div>

        {/* Footer - Fixed & Bottom */}
        {footer && (
          <div className="shrink-0 p-6 border-t border-[var(--border)] bg-[var(--bg-surface)]/95 backdrop-blur-md z-10 shadow-[0_-10px_20px_-10px_rgba(0,0,0,0.1)]">
            {footer}
          </div>
        )}
      </div>
    </div>
  );

  return createPortal(modalContent, document.body);
}

'use server';
import { createClient as createSupabaseClient } from '@supabase/supabase-js';
import { createClient as createServerClient } from '@/lib/supabase/server';

/**
 * Erstellt einen Supabase-Client mit Admin-Rechten (Server-Side only)
 */
async function createAdminClient() {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
  const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;
  const schema = process.env.NEXT_PUBLIC_SCHEMA || 'away-dev';

  if (!supabaseUrl || !supabaseServiceKey) {
    throw new Error('Supabase Credentials fehlen in .env.local');
  }

  return createSupabaseClient(supabaseUrl, supabaseServiceKey, {
    db: { schema },
    auth: {
      autoRefreshToken: false,
      persistSession: false
    }
  });
}

/**
 * Erzwingt einen Rollenwechsel für den aktuellen Benutzer.
 * Nutzt den Service Role Key, um jegliche RLS-Einschränkungen zu umgehen.
 */
export async function toggleUserRoleAction(newRole: string) {
  try {
    const supabase = await createServerClient();
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) throw new Error('Nicht authentifiziert');

    const userId = session.user.id;
    const admin = await createAdminClient();

    // 1. Organisation ermitteln
    // Wir suchen nach der ersten verfügbaren Organisation als primäres Ziel
    const { data: orgs, error: orgError } = await admin
      .from('organizations')
      .select('id')
      .limit(1);

    if (orgError) {
      console.error('Org Fetch Error:', orgError);
      throw new Error(`Konnte Organisationen nicht laden: ${orgError.message}`);
    }

    const orgId = orgs && orgs.length > 0 ? orgs[0].id : null;

    if (!orgId) {
      throw new Error('Keine Organisation im Datenbank-Schema gefunden. Bitte erst eine Organisation anlegen.');
    }

    console.log(`[DEBUG] Nutzer ${userId} wechselt zu Rolle "${newRole}" in Org "${orgId}"`);

    // 2. Bestehende Rollen in DIESER Organisation löschen
    const { error: deleteError } = await admin
      .from('user_roles')
      .delete()
      .eq('user_id', userId)
      .eq('organization_id', orgId);

    if (deleteError) {
      console.error('Delete Role Error:', deleteError);
    }

    // 3. Neue Rolle einfügen
    const { error: insertError } = await admin
      .from('user_roles')
      .insert({
        user_id: userId,
        organization_id: orgId,
        role: newRole
      });

    if (insertError) {
      console.error('Insert Role Error:', insertError);
      throw new Error(`Rollenwechsel fehlgeschlagen: ${insertError.message}`);
    }

    return { success: true, newRole };
  } catch (err: any) {
    console.error('SERVER ACTION ERROR:', err);
    throw new Error(err.message || 'Interner Server-Fehler beim Rollenwechsel');
  }
}

import { PDFDocument } from 'pdf-lib';
import * as XLSX from 'xlsx';
import Docxtemplater from 'docxtemplater';
import PizZip from 'pizzip';

export interface DocumentData {
  from: string;
  to: string;
  reason: string;
  deputy: string;
  notes: string;
  userEmail: string;
  orgName: string;
  date: string;
  customFields?: Record<string, any>;
}

/**
 * PDF Generation logic (Fill existing form or create new)
 */
export async function generatePDF(data: DocumentData, templateBytes?: ArrayBuffer): Promise<Blob> {
  if (templateBytes) {
    const pdfDoc = await PDFDocument.load(templateBytes);
    const form = pdfDoc.getForm();
    const fields = form.getFields();

    // Field name mapping logic
    const fieldMap: Record<string, string> = {
      from: data.from,
      to: data.to,
      reason: data.reason,
      deputy: data.deputy,
      notes: data.notes,
      email: data.userEmail,
      org: data.orgName,
      date: data.date,
      ...data.customFields
    };

    for (const field of fields) {
      const name = field.getName().toLowerCase();
      // Handle Checkboxes
      if (field.constructor.name === 'PDFCheckBox') {
        for (const [key, value] of Object.entries(fieldMap)) {
          if (name.includes(key.toLowerCase()) && typeof value === 'boolean') {
            const cb = form.getCheckBox(field.getName());
            if (value) cb.check(); else cb.uncheck();
            break;
          }
        }
        continue;
      }

      // Handle Text Fields
      for (const [key, value] of Object.entries(fieldMap)) {
        if (name.includes(key.toLowerCase()) && value) {
          try {
            const tf = form.getTextField(field.getName());
            tf.setText(String(value));
          } catch { /* field type mismatch */ }
          break;
        }
      }
    }
    const bytes = await pdfDoc.save();
    return new Blob([bytes.buffer as ArrayBuffer], { type: 'application/pdf' });
  }

  // Fallback: Create simple PDF
  const doc = await PDFDocument.create();
  const page = doc.addPage([595.28, 841.89]);
  const { height } = page.getSize();

  page.drawText('URLAUBSANTRAG', { x: 50, y: height - 80, size: 22 });
  page.drawText(`Organisation: ${data.orgName}`, { x: 50, y: height - 120, size: 12 });
  page.drawText(`Name: ${data.customFields?.firstName} ${data.customFields?.lastName}`, { x: 50, y: height - 145, size: 12 });
  page.drawText(`Von: ${data.from}`, { x: 50, y: height - 170, size: 12 });
  page.drawText(`Bis: ${data.to}`, { x: 200, y: height - 170, size: 12 });
  page.drawText(`Tage: ${data.customFields?.vacationDays}`, { x: 350, y: height - 170, size: 12 });

  page.drawText(`Grund: ${data.reason}`, { x: 50, y: height - 210, size: 12 });
  page.drawText(`Personalnr: ${data.customFields?.employeeId}`, { x: 50, y: height - 235, size: 11 });
  page.drawText(`Belegnr: ${data.customFields?.documentId}`, { x: 200, y: height - 235, size: 11 });

  page.drawText(`Ort: ${data.customFields?.location}`, { x: 50, y: height - 270, size: 11 });
  page.drawText(`Datum: ${data.customFields?.signedAt}`, { x: 200, y: height - 270, size: 11 });

  const bytes = await doc.save();
  return new Blob([bytes.buffer as ArrayBuffer], { type: 'application/pdf' });
}

/**
 * Excel Generation (SheetJS)
 */
export async function generateExcel(data: DocumentData, templateBytes?: ArrayBuffer): Promise<Blob> {
  let workbook: XLSX.WorkBook;

  if (templateBytes) {
    workbook = XLSX.read(templateBytes, { type: 'array' });
    const sheetName = workbook.SheetNames[0];
    const sheet = workbook.Sheets[sheetName];

    XLSX.utils.sheet_add_aoa(sheet, [
      ['Name', `${data.customFields?.firstName} ${data.customFields?.lastName}`],
      ['Personalnr', data.customFields?.employeeId],
      ['Von', data.from],
      ['Bis', data.to],
      ['Tage', data.customFields?.vacationDays],
      ['Grund', data.reason]
    ], { origin: -1 }); 
  } else {
    workbook = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet([{
      'Vorname': data.customFields?.firstName,
      'Nachname': data.customFields?.lastName,
      'Personalnr': data.customFields?.employeeId,
      'Organisation': data.orgName,
      'Von': data.from,
      'Bis': data.to,
      'Tage': data.customFields?.vacationDays,
      'Grund': data.reason,
      'Ort': data.customFields?.location,
      'Datum': data.customFields?.signedAt
    }]);
    XLSX.utils.book_append_sheet(workbook, ws, 'Urlaub');
  }

  const out = XLSX.write(workbook, { type: 'array', bookType: 'xlsx' });
  return new Blob([out], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
}

/**
 * Word Generation (docxtemplater + pizzip)
 */
export async function generateWord(data: DocumentData, templateBytes: ArrayBuffer): Promise<Blob> {
  const zip = new PizZip(templateBytes);
  const doc = new Docxtemplater(zip, {
    paragraphLoop: true,
    linebreaks: true,
  });

  doc.render({
    from: data.from,
    to: data.to,
    reason: data.reason,
    deputy: data.deputy,
    notes: data.notes,
    userEmail: data.userEmail,
    orgName: data.orgName,
    date: data.date,
    ...data.customFields
  });

  const out = doc.getZip().generate({
    type: 'blob',
    mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  });

  return out;
}

import { createClient } from '@/lib/supabase/client';

export type VacationStatus = 'pending' | 'approved' | 'rejected';

export interface VacationRequest {
  id: string;
  user_id: string;
  organization_id: string;
  from: string;
  to: string;
  reason: string;
  status: VacationStatus;
  created_at: string;
  template_fields?: Record<string, any>;
}

export interface VacationRequestInput {
  userId: string;
  organizationId: string;
  from: string;
  to: string;
  reason: string;
}

export async function createVacationRequest({ userId, organizationId, from, to, reason }: VacationRequestInput) {
  const supabase = createClient();
  const { data, error } = await supabase
    .from('vacation_requests')
    .insert([{ user_id: userId, organization_id: organizationId, from, to, reason, status: 'pending' }]);
  if (error) throw error;
  return data;
}

export async function getVacationRequestsForOrg(organizationId: string): Promise<VacationRequest[]> {
  const supabase = createClient();
  const { data, error } = await supabase
    .from('vacation_requests')
    .select('*')
    .eq('organization_id', organizationId)
    .order('created_at', { ascending: false });
  if (error) throw error;
  return (data as VacationRequest[]) || [];
}

export async function getMyVacationRequests(userId: string): Promise<VacationRequest[]> {
  const supabase = createClient();
  const { data, error } = await supabase
    .from('vacation_requests')
    .select('*')
    .eq('user_id', userId)
    .order('created_at', { ascending: false });
  if (error) throw error;
  return (data as VacationRequest[]) || [];
}

export async function updateVacationStatus(requestId: string, status: VacationStatus) {
  const supabase = createClient();
  const { data, error } = await supabase
    .from('vacation_requests')
    .update({ status })
    .eq('id', requestId)
    .select('*')
    .single();
  if (error) throw error;
  return data as VacationRequest;
}
